window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q17"]=window.__LIBQ["tien-nghich"]["q17"]||{};window.__LIBQ["tien-nghich"]["q17"]["artifacts"]={"updatedAt":"2026-07-16","count":102,"artifacts":[{"id":"giai-hon-tien-qua","name":"Giải Hồn tiên quả","cn":"","aliases":["Giải Hồn Quả"],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Nam đệ tử Đại Hồn Môn"],"trangThai":"đang được đưa tới các sư tỷ","blurb":"Vật phẩm được nhắc tới trong Đại Hồn Môn khi một nam đệ tử bị thúc giục mau đưa cho các sư tỷ. Công dụng cụ thể chưa được nêu rõ trong chương này.","detail":"Giải Hồn tiên quả xuất hiện qua lời thúc giục của tu sĩ Đại Hồn Môn đối với nam đệ tử bị Vương Lâm nhập thân. Việc giao vật phẩm này cho các sư tỷ bị coi là không thể chậm trễ, nhưng công năng cụ thể chưa được nói rõ.","dinhDanh":"goc","congNang":["Chưa rõ công dụng cụ thể, chỉ biết đang được đưa cho các sư tỷ trong Đại Hồn Môn @c1725"],"chuHienThoi":"Nam đệ tử Đại Hồn Môn","chuSoHuu":[{"ten":"Nam đệ tử Đại Hồn Môn","tuChuong":"@c1725","denChuong":"","cachCoDuoc":"đang mang đi giao cho các sư tỷ","trangThai":"đang giữ"}],"capNhatToi":"@c1725","tabs":{"tienTrinh":[{"chuong":"@c1725","loai":"xuất hiện","importance":"normal","giaiDoan":"được đưa cho các sư tỷ","text":"Giải Hồn tiên quả được nam đệ tử Đại Hồn Môn mang đi giao cho các sư tỷ, và việc chậm trễ bị người bên cạnh khiển trách.","anchor":"nếu làm chậm trễ thời gian đưa Giải Hồn Quả cho chư vị sư tỷ thì chúng ta không đảm đương nổi đâu"}]},"nguon":["@c1725"]},{"id":"ngoc-gian-mo-tang-sang","name":"Ngọc giản mở tầng sáng","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Tống Anh"],"trangThai":"đang dùng","blurb":"Ngọc giản mà Tống Anh dùng để mở tầng sáng phòng hộ bên ngoài Viêm Mạch Phong. Vương Lâm nhân cơ hội này nghiên cứu cấm chế bên trong để mô phỏng và xâm nhập.","detail":"Ngọc giản chứa cấm chế liên quan tới tầng sáng phòng hộ của ngọn núi đỏ rực. Khi Tống Anh mở phòng hộ, Vương Lâm đưa một phần thần thức vào nghiên cứu, sau đó dùng cấm chế bổn nguyên mô phỏng lại cơ chế của ngọc giản.","hinhDang":"ngọc giản","congNang":["Mở tầng sáng phòng hộ bên ngoài Viêm Mạch Phong @c1726"],"chuSoHuu":[{"ten":"Tống Anh","tuChuong":"@c1726","denChuong":"","cachCoDuoc":"vật dụng khi làm nhiệm vụ trong Đại Hồn Môn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1726","loai":"dùng","importance":"normal","giaiDoan":"Mở tầng sáng Viêm Mạch Phong","text":"Tống Anh dùng ngọc giản mở tầng sáng phòng hộ bên ngoài Viêm Mạch Phong, tạo cơ hội để Vương Lâm nghiên cứu cấm chế bên trong.","anchor":"lấy cấm chế bổn nguyên mô phỏng lại ngọc giản vừa rồi, vô thanh vô tức tiến vào bên trong"}]},"capNhatToi":"@c1726","nguon":["@c1726"]},{"id":"co-kinh-dong-xanh","name":"Cổ kính đồng xanh","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Viêm Loan"],"trangThai":"đang dùng","blurb":"Pháp bảo màu đồng xanh của Viêm Loan, được lấy ra trong lúc truy kích Vương Lâm dưới địa hỏa chủ mạch.","detail":"Cổ kính có màu đồng xanh, tỏa ánh sáng vạn trượng, mang đạo văn và có thể phóng hắc khí hóa thành mặt quỷ để truy sát mục tiêu.","phanLoaiPhu":"Cổ kính","hinhDang":"Cổ kính màu đồng xanh","dacDiem":"Có đạo văn, khi xuất hiện hóa thành hình ảnh thiên địa và tỏa ánh sáng mạnh.","chuHienThoi":"Viêm Loan","congNang":["Phóng hắc khí hóa thành mặt quỷ truy sát mục tiêu @c1728"],"chuSoHuu":[{"ten":"Viêm Loan","tuChuong":"@c1728","denChuong":"","cachCoDuoc":"Đã sở hữu khi truy kích Vương Lâm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1728","loai":"dùng","importance":"normal","giaiDoan":"Truy sát Vương Lâm","text":"Viêm Loan lấy cổ kính đồng xanh ra, dùng nó phóng hắc khí hóa thành mặt quỷ truy sát Vương Lâm trong địa hỏa chủ mạch.","anchor":"liền có một cổ kính màu đồng xanh biến ảo ra"}]},"capNhatToi":"@c1728","nguon":["@c1728"]},{"id":"huyen-la-kim-an","name":"Huyền La kim ấn","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo mang khí tức Đại Thiên Tôn","soHuu":["Vương Lâm"],"trangThai":"đã dùng trong giao chiến","blurb":"Huyền La kim ấn là kim ấn mang một tia lực lượng của Huyền La. Vương Lâm dùng nó phá tan mặt quỷ của Viêm Loan trong địa hỏa chủ mạch.","detail":"Kim ấn được Vương Lâm vung tay áo phóng ra, tỏa khí tức cường hãn ẩn chứa lực lượng Huyền La. Khi va chạm, kim ấn nổ tung tạo kim quang vạn trượng, phá tan mặt quỷ Không Kiếp và khiến Viêm Loan chấn kinh vì cảm nhận khí tức Đại Thiên Tôn.","nguonGoc":"Đại Thiên Tôn Huyền La dùng thần thông ngưng tụ ban tặng.","uyLuc":"Phá tan mặt quỷ của tu sĩ Không Kiếp Đại Hồn Môn.","dacDiem":"Ẩn chứa một tia lực lượng của Huyền La và khí tức Đại Thiên Tôn.","congNang":["Tấn công mạnh bằng kim quang và khí tức Đại Thiên Tôn Huyền La @c1729"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1729","denChuong":"","cachCoDuoc":"Được Huyền La ban tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1729","loai":"dùng","importance":"normal","giaiDoan":"Phá tan mặt quỷ","text":"Vương Lâm phóng Huyền La kim ấn, dùng khí tức Đại Thiên Tôn phá tan mặt quỷ của Viêm Loan.","anchor":"Từ trong kim ấn tỏa ra khí tức cường hãn, hơn nữa còn ẩn chứa một tia lực lượng của Huyền La"}]},"capNhatToi":"@c1729","nguon":["@c1729"]},{"id":"ngoc-gian-dai-hon-mon","name":"Ngọc giản Đại Hồn Môn","cn":"","aliases":[],"category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang do Vương Lâm giữ","blurb":"Ngọc giản do Thanh Ngưu chân nhân trao cho Vương Lâm sau khi công nhận hắn là trưởng lão Đại Hồn Môn.","detail":"Vật này cho phép Vương Lâm tùy ý ra vào hầu hết cấm chế của Đại Hồn Môn, là tín vật thông hành đi kèm thân phận trưởng lão mới.","phanLoaiPhu":"lệnh bài thông hành","hinhDang":"ngọc giản","congNang":["Cho phép tùy ý ra vào hầu hết cấm chế của Đại Hồn Môn @c1735"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1735","denChuong":"","cachCoDuoc":"Thanh Ngưu chân nhân trao khi công nhận làm trưởng lão Đại Hồn Môn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1735","loai":"đổi chủ","importance":"normal","giaiDoan":"Trao cho trưởng lão mới","text":"Thanh Ngưu chân nhân trao ngọc giản cho Vương Lâm để hắn ra vào phần lớn cấm chế Đại Hồn Môn.","anchor":"Miếng ngọc giản này có thể tùy ý đi vào hầu hết cấm chế của Đại Hồn Môn!"}]},"capNhatToi":"@c1735","nguon":["@c1735"]},{"id":"ba-phan-le-vat-to-tien-dai-hon-mon","name":"Ba phần lễ vật tổ tiên Đại Hồn Môn","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"chưa giao","blurb":"Ba phần lễ vật do tổ tiên Đại Hồn Môn chuẩn bị sẵn cho Vương Lâm, được Thanh Ngưu chân nhân hứa trao sau ba ngày.","detail":"Thanh Ngưu chân nhân nói ba phần lễ vật này đã chuẩn bị từ rất lâu và sẽ thay mặt tổ tiên tặng cho Vương Lâm tại Thanh Thiên Phong sau ba ngày; chi tiết và công dụng cụ thể chưa lộ rõ trong chương này.","nguonGoc":"Tổ tiên Đại Hồn Môn chuẩn bị từ lâu.","dacDiem":"Có công dụng trọng yếu đối với Vương Lâm nhưng nội dung cụ thể chưa được tiết lộ.","chuHienThoi":"Thanh Ngưu chân nhân giữ, dự định trao cho Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1735","denChuong":"","cachCoDuoc":"Được Thanh Ngưu chân nhân hứa thay mặt tổ tiên trao sau ba ngày","trangThai":"chưa nhận"}],"tabs":{"tienTrinh":[{"chuong":"@c1735","loai":"nhắc tới","importance":"normal","giaiDoan":"Hẹn trao tại Thanh Thiên Phong","text":"Thanh Ngưu chân nhân nói ba phần lễ vật tổ tiên Đại Hồn Môn đã chuẩn bị từ lâu và sẽ trao cho Vương Lâm sau ba ngày.","anchor":"ba phần lễ vật này lão phu liền thay mặt tổ tiên tặng cho ngươi"}]},"capNhatToi":"@c1735","nguon":["@c1735"]},{"id":"hon-nhan","name":"Hồn nhân","aliases":["người tí hon"],"category":"phap-bao","categoryLabel":"Thể suy diễn","phamCap":"Sản vật tiểu thành Hồn Diễn Đạo","soHuu":["Vương Lâm"],"trangThai":"được Vương Lâm thu hồi nuôi dưỡng","blurb":"Hồn nhân là người tí hon cao ba tấc do Hồn Diễn Đạo tiểu thành của Vương Lâm ngưng tụ, sinh ra từ hồn khí nơi mi tâm sau khi hoàn thành mười vạn minh tự. Vật này dùng để bái lạy và khai mở cảnh tượng suy diễn tương lai.","detail":"Sau khi Vương Lâm hoàn thành mười vạn minh tự, hồn khí từ mi tâm bay ra và ngưng thành một người tí hon cao ba tấc (@c1736). Thân thể hồn nhân do mười vạn ký hiệu minh tự có lạc ấn linh hồn biến thành, chỉ có đôi mắt, không có mũi, miệng hay tai. Khi bái lạy, hồn nhân có thể mở ra cảnh tượng suy diễn tương lai. Sau bốn lần bái lạy để Vương Lâm nhìn thấy cảnh bản thân bị trấn áp dưới lôi sơn, hồn nhân trở nên uể oải và được thu hồi nuôi dưỡng (@c1736).","phanLoaiPhu":"hồn thể suy diễn","hinhDang":"người tí hon cao ba tấc, chỉ có đôi mắt","nguonGoc":"Hồn Diễn Đạo tiểu thành","uyLuc":"Bái lạy để khai mở cảnh tượng suy diễn tương lai.","dacDiem":"Do mười vạn minh tự có lạc ấn linh hồn tạo thành, cao ba tấc, chỉ có đôi mắt mà không có mũi, miệng hay tai; sau khi vận dụng mạnh sẽ suy yếu.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1736","denChuong":"","cachCoDuoc":"Ngưng tụ khi đạt tiểu thành Hồn Diễn Đạo.","trangThai":"đang giữ"}],"congNang":["Bái lạy để khai mở cảnh tượng suy diễn tương lai @c1736"],"tabs":{"tienTrinh":[{"chuong":"@c1736","loai":"xuất hiện","importance":"major","giaiDoan":"ngưng tụ lần đầu","text":"Hồn nhân được Vương Lâm ngưng tụ khi đạt tiểu thành Hồn Diễn Đạo, sau đó bái lạy bốn lần để mở cảnh tượng tương lai rồi suy yếu.","anchor":"hóa thành một người tí hon. Kẻ này chỉ lớn cỡ ba tắc, thân thể là do mười vạn ký hiệu minh tự","phamCap":"Sản vật tiểu thành Hồn Diễn Đạo"}]},"capNhatToi":"@c1736","nguon":["@c1736"]},{"id":"chiec-o-mau-lam-cua-viem-loan","name":"Chiếc ô màu lam của Viêm Loan","cn":"","aliases":["Chiếc ô màu lam","Ô lam","Cây ô màu lam của Viêm Loan"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Viêm Loan"],"trangThai":"Được Viêm Loan đem ra làm vật đánh cuộc","blurb":"Pháp bảo màu lam của Viêm Loan, xuất hiện khi nàng chấp nhận đánh cuộc với Vương Lâm. Công năng cụ thể chưa được lộ trong chương này.","detail":"Viêm Loan vung tay phải gọi ra chiếc ô màu lam trước mặt, dùng nó làm vật đặt cược cho lời thách rằng nếu Vương Lâm bước lên tầng bảy Tàng Hồn Các thì nàng sẽ đem vật này đánh cuộc.","phanLoaiPhu":"Pháp bảo dạng ô","hinhDang":"Một chiếc ô màu lam","dacDiem":"Được Viêm Loan tự tin lấy ra làm vật đánh cuộc.","chuHienThoi":"Viêm Loan","chuSoHuu":[{"ten":"Viêm Loan","tuChuong":"@c1738","denChuong":"","cachCoDuoc":"Đang nắm giữ trước khi đặt cược","trangThai":"đang giữ"}],"congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c1738","loai":"xuất hiện","importance":"normal","giaiDoan":"Vật đánh cuộc","text":"Viêm Loan gọi ra chiếc ô màu lam và dùng nó làm vật đánh cuộc với Vương Lâm.","anchor":"tay phải vung lên. Một chiếc ô màu lam xuất hiện trước mặt nàng"}]},"capNhatToi":"@c1738","nguon":["@c1738"]},{"id":"ho-lo-mau-tim-cua-la-van-hai","name":"Hồ lô màu tím của La Vân Hải","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Viêm Loan","La Vân Hải"],"trangThai":"tổn hại, còn một lần thi triển","blurb":"Hồ lô màu tím là pháp bảo của đệ cửu Tiên Tổ La Vân Hải lúc còn sống, được Viêm Loan lấy ra làm vật cược mới với Vương Lâm. Tuy đã tổn hại, nó vẫn còn chứa ba ngàn vạn đạo hồn và một lần thi triển tối hậu.","detail":"Hồ lô màu tím vốn thuộc về đệ cửu Tiên Tổ La Vân Hải khi ngài còn sống. Pháp bảo này từng ngưng tụ mười triệu đạo hồn, nhưng sau khi bị tổn hại nay chỉ còn ba ngàn vạn đạo hồn và duy nhất một lần thi triển. Dù vậy, một lần thi triển ấy có thể phát huy lực lượng tối cường của tu sĩ Không Kiếp trung kỳ. Hồ lô còn là chìa khóa phối hợp cùng Hồn Diễn Quy Đạo Thuật để triệu gọi đệ cửu Tiên Tổ giáng xuống. Tại mốc xuất hiện, Viêm Loan đã lấy nó ra làm vật cược mới trong cuộc đấu với Vương Lâm.","phanLoaiPhu":"Hồn đạo pháp bảo","nguonGoc":"Pháp bảo của đệ cửu Tiên Tổ La Vân Hải lúc còn sống","uyLuc":"Có thể phát huy lực lượng tu sĩ Không Kiếp trung kỳ tối cường trong một lần thi triển.","dacDiem":"Chứa ba ngàn vạn đạo hồn sau khi đã tổn hại.","chuHienThoi":"Viêm Loan","congNang":["Chứa ba ngàn vạn đạo hồn và còn một lần thi triển @c1740","Kết hợp Hồn Diễn Quy Đạo Thuật có thể gọi đệ cửu Tiên Tổ giáng xuống @c1740"],"chuSoHuu":[{"ten":"La Vân Hải","tuChuong":"@c1740","denChuong":"","cachCoDuoc":"Chủ nhân lúc sinh tiền","trangThai":"chủ cũ"},{"ten":"Viêm Loan","tuChuong":"@c1740","denChuong":"","cachCoDuoc":"Vô ý đạt được sau này","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1740","loai":"xuất hiện","importance":"major","giaiDoan":"Vật cược tầng tám","text":"Viêm Loan lấy hồ lô màu tím của La Vân Hải làm vật cược mới, hé lộ lai lịch, số đạo hồn còn lại, uy lực một lần thi triển và công năng phối hợp Hồn Diễn Quy Đạo Thuật.","anchor":"Vật này là Pháp Bảo của đệ cửu Tiên Tổ La Vân Hải lúc còn sống","phamCap":"Không rõ"}]},"capNhatToi":"@c1740","nguon":["@c1740"]},{"id":"ho-lo-cua-viem-loan","name":"Hồ lô của Viêm Loan","cn":"","aliases":["Hồ lô vật đánh cược"],"category":"phap-bao","categoryLabel":"Pháp bảo/vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đổi chủ sang Vương Lâm","blurb":"Hồ lô của Viêm Loan là vật cược nàng đặt ra trong lần đánh cuộc với Vương Lâm tại Tàng Hồn Các. Sau khi thua cược, hồ lô rời khỏi tay nàng và đổi chủ về Vương Lâm.","detail":"Hồ lô này vốn thuộc về Viêm Loan, được nàng dùng làm vật cược trong lần đánh cuộc với Vương Lâm tại Tàng Hồn Các. Khi Vương Lâm thắng cược, một lực hút kéo hồ lô về phía hắn nhưng Viêm Loan cắn răng cố giữ lại. Đến lúc nàng bị khí thế phân thân của Vương Lâm trấn áp, hồ lô rời khỏi tay nàng và bay thẳng vào tay Vương Lâm, chính thức đổi chủ @c1741.","chuHienThoi":"Vương Lâm","congNang":["Là vật cược, bị lực hút kéo về phía người thắng cược sau khi Vương Lâm thắng @c1741"],"chuSoHuu":[{"ten":"Viêm Loan","tuChuong":"@c1741","denChuong":"@c1741","cachCoDuoc":"Vật vốn ở trong tay Viêm Loan và được dùng làm vật đánh cược.","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1741","denChuong":"","cachCoDuoc":"Thắng cược Viêm Loan rồi dùng khí thế phân thân trấn áp khiến nàng buông tay.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1741","loai":"đổi chủ","importance":"major","giaiDoan":"Từ Viêm Loan sang Vương Lâm","text":"Hồ lô vốn là vật cược của Viêm Loan; sau khi nàng bị trấn áp và buông tay, nó bay vào tay Vương Lâm.","anchor":"Hồ lô trong đó lập tức nhoáng lên, bay về phía Vương Lâm"}]},"capNhatToi":"@c1741","nguon":["@c1741"]},{"id":"chin-hon-the-tang-tam-tang-hon-cac","name":"Chín hồn thể tầng tám Tàng Hồn Các","cn":"","aliases":["Chín hồn thể"],"category":"khac","categoryLabel":"Hồn thể chứa thần thông","phamCap":"Không rõ","soHuu":["Đại Hồn Môn"],"trangThai":"đang lưu giữ tại tầng tám Tàng Hồn Các","blurb":"Chín hồn thể lơ lửng trong tầng tám Tàng Hồn Các, mỗi hồn thể chứa một thần thông cực mạnh của Đại Hồn Môn.","detail":"Tầng tám Tàng Hồn Các phủ đầy tro bụi vì lâu không có người tới. Bên trong có chín hồn thể tỏa ánh sáng nhu hòa, là vật chứa truyền thừa cho chín thần thông mạnh mẽ của Đại Hồn Môn.","hinhDang":"Hồn thể lơ lửng, tỏa ánh sáng nhu hòa.","nguonGoc":"Tàng Hồn Các tầng tám của Đại Hồn Môn","congNang":["Chứa và truyền thừa chín thần thông cực mạnh của Đại Hồn Môn @c1741"],"chuSoHuu":[{"ten":"Đại Hồn Môn","tuChuong":"@c1741","denChuong":"","cachCoDuoc":"Được cất giữ trong tầng tám Tàng Hồn Các của tông môn.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1741","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ trong tầng tám","text":"Vương Lâm vào tầng tám Tàng Hồn Các và nhìn thấy chín hồn thể chứa thần thông của Đại Hồn Môn.","anchor":"Ở tầng này lơ lửng chín hồn thể, tỏa ra ánh sáng nhu hòa"}]},"capNhatToi":"@c1741","nguon":["@c1741"]},{"id":"ba-hop-gam","name":"Ba hộp gấm","cn":"","aliases":["Ba hộp gấm lễ vật Thanh Ngưu lão tổ tặng Vương Lâm"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"chưa mở","blurb":"Ba hộp gấm là lễ vật Thanh Ngưu lão tổ tặng Vương Lâm. Cuối chương Vương Lâm mới nhìn vào một hộp, nội dung bên trong chưa lộ.","detail":"Sau khi trở về động phủ cao nhất trên ngọn núi cháy, Vương Lâm lấy ra ba hộp gấm do Thanh Ngưu lão tổ tặng. Hắn cho rằng người tính ra việc mình sẽ tới đã chuẩn bị lễ vật này, nhưng chương kết khi hắn mới nhìn vào một hộp nên chưa rõ bên trong là gì.","phanLoaiPhu":"lễ vật","hinhDang":"ba hộp gấm","nguonGoc":"Thanh Ngưu lão tổ tặng Vương Lâm","dacDiem":"Nội dung chưa được mở ra trong chương.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1742","denChuong":"","cachCoDuoc":"nhận lễ vật từ Thanh Ngưu lão tổ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1742","loai":"xuất hiện","importance":"normal","giaiDoan":"lễ vật chưa mở","text":"Vương Lâm lấy ra ba hộp gấm do Thanh Ngưu lão tổ tặng và chuẩn bị xem lễ vật bên trong.","anchor":"Ba hộp gấm này chính là ba lễ vật Thanh Ngưu lão tổ tặng hắn"}]},"capNhatToi":"@c1742","nguon":["@c1742"]},{"id":"khong-gian-thach","name":"Không Gian Thạch","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Không Gian Thạch là lễ vật thứ nhất của tiền nhân Đại Hồn Môn dành cho Vương Lâm, một hòn đá đen mà mỗi lỗ nhỏ trên bề mặt là một không gian độc lập. Tính tới mốc mới nhất, nó vừa là côngụ mở Không Gian trữ vật giữa pháp tắc Tiên Cương đại lục, vừa là nơi Vương Lâm có thể thân hành tiến vào đểận dụng liên quan tới U Minh Thú.","detail":"Không Gian Thạch do tiền nhân Đại Hồn Môn trao cho Vương Lâm làm lễ vật thứ nhất (@c1743). Bề mặt đá phủ đầy lỗ nhỏ, mỗi lỗ là một không gian độc lập; hủy một không gian trong đó cho phép mở Không Gian trữ vật một lần giữa pháp tắc Tiên Cương đại lục mà không hao tổn vật bên trong, song cách dùng này chỉ thực hiện được một lần trước khi đá tan vỡ. Ngoài công năng trữ vật, đá còn có thể nuôi dưỡng Thiên Đạo không hoàn chỉnh để dần hoàn thiện (@c1743). Về sau Vương Lâm lần đầu đưa thân thể tiến vào Không Gian Thạch, hiểu thêm các công dụng liên quan tới U Minh Thú và vận dụng đá làm nền cho một sát trận phục kích (@c1769).","phanLoaiPhu":"dị bảo không gian","hinhDang":"Hòn đá đen cỡ nắm tay, bề mặt có vô số lỗ nhỏ.","chuHienThoi":"Vương Lâm","congNang":["Hủy một không gian trong đá để mở Không Gian trữ vật một lần mà không hao tổn đồ bên trong @c1743","Nuôi dưỡng Thiên Đạo không hoàn chỉnh để chậm rãi hoàn chỉnh @c1743","Chứa không gian bên trong để Vương Lâm thân hành tiến vào @c1769","Tăng mạnh khả năng cắn nuốt của U Minh Thú @c1769","Làm nền cho sát trận phục kích @c1769"],"dacDiem":"Mỗi lỗ nhỏ trên đá là một không gian độc lập; dùng quá một lần theo cách mở Không Gian trữ vật sẽ khiến đá tan vỡ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1743","denChuong":"","cachCoDuoc":"Đang sở hữu và khai dụng trong truy sát","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1743","loai":"đổi chủ","importance":"major","giaiDoan":"Lễ vật thứ nhất","text":"Không Gian Thạch được trao cho Vương Lâm, lộ hai công năng là mở Không Gian trữ vật một lần và nuôi dưỡng Thiên Đạo không hoàn chỉnh.","anchor":"Đây là một khối Không Gian Thạch. Là lễ vật đầu tiên ta chuấn bị cho ngài","phamCap":"không rõ"},{"chuong":"@c1769","loai":"khai phong","importance":"major","giaiDoan":"Thân thể tiến vào","text":"Vương Lâm lần đầu đưa thân thể vào Không Gian Thạch, hiểu thêm công dụng liên quan tới U Minh Thú và dùng không gian bên trong để dựng sát trận.","anchor":"Đây là lần đầu tiên thân thể hắn tiến vào trong hòn đá kỳ dị này."}]},"capNhatToi":"@c1743","nguon":["@c1743","@c1769"]},{"id":"ngoc-gian-hon-dien-dao","name":"Ngọc giản Hồn Diễn đạo","cn":"","aliases":["Ngọc giản sương mù"],"category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm, còn một lần sử dụng","blurb":"Ngọc giản Hồn Diễn đạo là lễ vật thứ hai dành cho Vương Lâm, do Hồn Diễn đạo suốt đời của giọng nói già nua biến thành. Ngọc giản hoàn toàn do sương mù tạo thành, bên trong có vô số thân ảnh giao nhau, được Vương Lâm xem là vật có thể bảo mệnh ở thời khắc mấu chốt.","detail":"Ngọc giản Hồn Diễn đạo xuất thân từ Hồn Diễn đạo suốt đời của giọng nói già nua biến thành, được trao cho Vương Lâm như lễ vật thứ hai (@c1743). Cả ngọc giản hoàn toàn do sương mù tạo thành, bên trong có vô số thân ảnh giao nhau. Công năng cốt lõi là vì Vương Lâm thi triển một lần Tiên Cương biến hóa, tính toán một việc hoặc một lần biến hóa quá khứ tương lai của bản thân hoặc người khác. Vì chỉ dùng được một lần, Vương Lâm xem nó là vật bảo mệnh dành cho thời khắc mấu chốt.","phanLoaiPhu":"dị bảo bói diễn","hinhDang":"Ngọc giản do sương mù tạo thành, chuyển động quỷ dị.","nguonGoc":"Do Hồn Diễn đạo suốt đời của giọng nói già nua biến thành.","chuHienThoi":"Vương Lâm","congNang":["Thi triển một lần Tiên Cương biến hóa để tính ra một việc hay biến hóa quá khứ tương lai của bản thân hoặc người khác @c1743"],"dacDiem":"Ngọc giản hoàn toàn do sương mù tạo thành, bên trong có vô số thân ảnh giao nhau; chỉ có một lần sử dụng; tâm thần khẽ động có thể chỉ định một người để tính toán.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1743","denChuong":"","cachCoDuoc":"Nhận làm lễ vật thứ hai từ tiền nhân Đại Hồn Môn.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1743","loai":"đổi chủ","importance":"major","giaiDoan":"Lễ vật thứ hai","text":"Ngọc giản Hồn Diễn đạo về tay Vương Lâm và lộ công năng thi triển một lần Tiên Cương biến hóa để suy tính chuyện trọng yếu.","anchor":"ngọc giản này là Hồn Diễn đạo suốt đời ta biến thành, có thể vì ngài thi triển một lần Tiên Cương biến hóa","phamCap":"không rõ"}]},"capNhatToi":"@c1743","nguon":["@c1743"]},{"id":"giot-thuy-bon-nguyen","name":"Giọt thủy bổn nguyên","cn":"","aliases":["Giọt nước mưa Thiên Hà châu"],"category":"nguyen-lieu","categoryLabel":"Dị bảo bổn nguyên","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm, chuẩn bị hấp thu","blurb":"Giọt thủy bổn nguyên là lễ vật thứ ba dành cho Vương Lâm, một giọt nước trong suốt lớn bằng ngón tay chứa thủy bổn nguyên cực kỳ nồng đậm, được luyện từ Thiên Hà châu. Tính tới khi về tay Vương Lâm, nó trở thành then chốt giúp thủy bổn nguyên của hắn tiến gần đại thành.","detail":"Giọt thủy bổn nguyên được luyện từ chín mươi chín dòng sông trên Thiên Hà châu, cộng thêm thủy bổn nguyên rút từ cơ thể nhiều tu sĩ. Vật có hình giọt nước trong suốt lớn bằng ngón tay, khí tức thủy bổn nguyên nồng đậm tới mức tràn ngập động phủ và khiến biển lửa ngoài núi có dấu hiệu bị dập tắt. Là lễ vật thứ ba dành cho Vương Lâm, sau khi về tay hắn (@c1743) nó trở thành then chốt giúp thủy bổn nguyên của Vương Lâm tiến gần đại thành; nếu hấp thu trọn vẹn, thủy bổn nguyên của hắn dù chưa viên mãn cũng chỉ còn kém một chút.","phanLoaiPhu":"dị bảo bổn nguyên thủy","hinhDang":"Giọt nước mưa trong suốt lớn bằng ngón tay, bên trong có vô số sương mù.","nguonGoc":"Luyện từ chín mươi chín dòng sông trên Thiên Hà châu và thủy bổn nguyên của nhiều tu sĩ.","chuHienThoi":"Vương Lâm","congNang":["Giúp thủy bổn nguyên của Vương Lâm sau khi hấp thu tiến sát viên mãn @c1743"],"dacDiem":"Giọt nước trong suốt lớn bằng ngón tay, khí tức thủy bổn nguyên nồng đậm tới mức có thể ảnh hưởng biển lửa quanh động phủ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1743","denChuong":"","cachCoDuoc":"Nhận làm lễ vật thứ ba từ tiền nhân Đại Hồn Môn.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1743","loai":"đổi chủ","importance":"major","giaiDoan":"Lễ vật thứ ba","text":"Giọt thủy bổn nguyên về tay Vương Lâm, trở thành then chốt giúp thủy bổn nguyên của hắn tiến gần đại thành.","anchor":"Vật này là do ta luyện hóa chín mươi chín dòng sôn trên Thiên Hà châu ngưng tụ thành","phamCap":"không rõ"}]},"capNhatToi":"@c1743","nguon":["@c1743"]},{"id":"ngoc-gian-ban-do-vung-bien-thien-nguu-chau-luc-ma-chau","name":"Ngọc giản bản đồ vùng biển Thiên Ngưu Châu — Lục Ma Châu","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản bản đồ","phamCap":"không rõ","soHuu":["Vương Lâm","Viêm Loan"],"trangThai":"Vương Lâm giữ sau khi nhận từ Viêm Loan","blurb":"Ngọc giản do Viêm Loan ghi lại lộ tuyến tới vùng biển giao giới Thiên Ngưu Châu và Lục Ma Châu. Vương Lâm nhận nó để rời Đại Hồn Môn đi tìm nơi hấp thu thủy bổn nguyên.","detail":"Viêm Loan dùng thần thức ghi bản đồ vào ngọc giản, chỉ đường tới vùng biển vô biên giữa hai đại châu rồi giao cho Vương Lâm. Chương nhấn mạnh nàng không động tay chân trong ngọc giản này.","dinhDanh":"goc","phanLoaiPhu":"ngọc giản bản đồ","congNang":["Ghi lộ tuyến tới vùng biển giao giới Thiên Ngưu Châu và Lục Ma Châu @c1745"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Viêm Loan","tuChuong":"@c1745","denChuong":"@c1745","cachCoDuoc":"Tự ghi thần thức bản đồ vào ngọc giản","trangThai":"đã giao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1745","denChuong":"","cachCoDuoc":"Nhận từ Viêm Loan sau khi hỏi nơi có nhiều nước","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1745","loai":"đổi chủ","importance":"normal","giaiDoan":"Viêm Loan giao bản đồ","text":"Viêm Loan ghi bản đồ tới vùng biển giữa Thiên Ngưu Châu và Lục Ma Châu vào ngọc giản rồi đưa cho Vương Lâm.","anchor":"thần thức dung nhập vào ghi lại bản đồ đi tới vùng biển giữa hai đại lục"}]},"capNhatToi":"@c1745","nguon":["@c1745"]},{"id":"an-ky-thuy-mac-tren-co-tay-vuong-lam","name":"Ấn ký thủy mặc trên cổ tay Vương Lâm","cn":"","aliases":["Ấn ký thủy mặc Văn Vương"],"category":"khac","categoryLabel":"Ấn ký triệu hoán","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang tồn tại trên cổ tay Vương Lâm","blurb":"Ấn ký như thủy mặc nằm trên cổ tay Vương Lâm, dùng để triệu xuất Văn Vương. Khi được kích phát, Văn Vương hiện thân và chở Vương Lâm vượt Cực Thiên thảo nguyên.","detail":"Trong hành trình tới vùng biển, từ ấn ký thủy mặc trên cổ tay Vương Lâm phát ra tiếng gào, sau đó Văn Vương biến ảo hiện thân. Ấn ký này gắn với khả năng gọi Văn Vương ra hỗ trợ di chuyển và chiến đấu.","dinhDanh":"goc","phanLoaiPhu":"ấn ký triệu hoán","congNang":["Triệu xuất Văn Vương từ cổ tay Vương Lâm @c1745"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1745","denChuong":"","cachCoDuoc":"Đã có trên cổ tay khi rời Đại Hồn Môn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1745","loai":"dùng","importance":"normal","giaiDoan":"Triệu xuất Văn Vương","text":"Ấn ký thủy mặc trên cổ tay Vương Lâm phát ra tiếng gào và khiến Văn Vương biến ảo hiện thân để nâng hắn bay đi.","anchor":"tràn ra từ ấn ký như thủy mặc trên cổ tay hắn"}]},"capNhatToi":"@c1745","nguon":["@c1745"]},{"id":"la-ban-dan-hai","name":"La bàn Đan Hải","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo dò xét","phamCap":"Không rõ","soHuu":["Nữ tử áo trắng chỉ huy Lục Ma Châu"],"trangThai":"đang được sử dụng","blurb":"La bàn do nữ tử áo trắng Lục Ma Châu dùng để chỉ huy chiến dịch Đan Hải. Nó hiển thị bản đồ chiến trường và phân biệt mục tiêu hai phe bằng điểm sáng.","detail":"La bàn tỏa u quang trong tay nữ tử áo trắng, hiện ra bản đồ bao quát Đan Hải. Điểm xanh biểu thị tu sĩ Lục Ma Châu, điểm trắng biểu thị tu sĩ Thiên Ngưu Châu, nhờ đó nàng điều động các tổ Lục Ma vệ truy sát mục tiêu.","hinhDang":"La bàn nằm trong tay nữ tử áo trắng, khi vận dụng tỏa u quang.","chuHienThoi":"Nữ tử áo trắng chỉ huy Lục Ma Châu","congNang":["Hiển thị bản đồ Đan Hải và điểm sáng đại diện tu sĩ hai phe @c1747","Hỗ trợ nữ tử áo trắng xác định tọa độ để điều động Lục Ma vệ truy sát mục tiêu @c1747"],"chuSoHuu":[{"ten":"Nữ tử áo trắng chỉ huy Lục Ma Châu","tuChuong":"@c1747","denChuong":"","cachCoDuoc":"Mang theo trong chiến dịch Đan Hải","trangThai":"đang giữ"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1747","loai":"dùng","importance":"normal","giaiDoan":"Chỉ huy chiến trường Đan Hải","text":"Nữ tử áo trắng dùng la bàn để quan sát bản đồ Đan Hải, phân biệt điểm xanh và điểm trắng rồi điều binh truy sát.","anchor":"la bàn trong lòng bàn tay phải lập tức tỏa ra từng luồng u quang"}]},"nguon":["@c1747"]},{"id":"tinh-hoa-o-dich","name":"Tịnh Hóa Ô Dịch","cn":"","category":"khac","categoryLabel":"Chí bảo chất lỏng","phamCap":"Chí bảo của Độc Ma Tông","soHuu":["Nữ tử áo trắng chỉ huy Lục Ma Châu"],"trangThai":"đang được sử dụng","blurb":"Tịnh Hóa Ô Dịch là chí bảo của Độc Ma Tông được đưa vào chiến dịch Đan Hải. Nó là giọt chất lỏng màu đen trong suốt, chứa khí tức thủy bổn nguyên tinh thuần.","detail":"Nữ tử áo trắng lấy ra Tịnh Hóa Ô Dịch khi bàn về việc tiêu diệt tu sĩ Thiên Ngưu Châu trong Đan Hải. Vật này liên quan trực tiếp tới thủy bổn nguyên và được nàng xem như chỗ dựa khiến đối phương khó có đường sống.","hinhDang":"Giọt chất lỏng màu đen trong suốt tỏa u quang.","nguonGoc":"Chí bảo của Độc Ma Tông.","chuHienThoi":"Nữ tử áo trắng chỉ huy Lục Ma Châu","congNang":["Chứa khí tức thủy bổn nguyên tinh thuần @c1747","Được dùng làm bảo đảm trong kế hoạch diệt tu sĩ Thiên Ngưu Châu tại Đan Hải @c1747"],"chuSoHuu":[{"ten":"Nữ tử áo trắng chỉ huy Lục Ma Châu","tuChuong":"@c1747","denChuong":"","cachCoDuoc":"Mang theo trong chiến dịch Đan Hải","trangThai":"đang giữ"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1747","loai":"xuất hiện","importance":"normal","giaiDoan":"Đưa vào chiến dịch Đan Hải","text":"Nữ tử áo trắng lấy Tịnh Hóa Ô Dịch của Độc Ma Tông ra, cho thấy vật này chứa thủy bổn nguyên tinh thuần và gắn với kế hoạch diệt tu sĩ trong Đan Hải.","anchor":"Có chí bảo của Độc Ma Tông - Tịnh Hóa Ô Dịch này ở đây"}]},"nguon":["@c1747"]},{"id":"ba-dai-ky-luc-ma-chau","name":"Ba đại kỳ Lục Ma Châu","cn":"","aliases":["Ba cây đại kỳ Lục Ma Châu"],"category":"phap-bao","categoryLabel":"Đại kỳ trận địa","phamCap":"Không rõ","soHuu":["Lục Ma Châu"],"trangThai":"cắm tại khu vực gần Lục Ma Châu trong Đan Hải","blurb":"Ba đại kỳ cắm sâu trong lòng biển Đan Hải, tạo thành trung tâm tập kết của quân Lục Ma Châu. Dưới ba kỳ là mấy ngàn tu sĩ và ba tu sĩ áo trắng chỉ huy chiến dịch.","detail":"Ba đại kỳ nằm gần phía Lục Ma Châu trong Đan Hải, là nơi mấy ngàn tu sĩ Lục Ma Châu trầm mặc chờ lệnh. Chúng đánh dấu khu vực chỉ huy và tập kết của chiến dịch đồ sát Đan Hải.","hinhDang":"Ba cây đại kỳ cắm sâu trong lòng biển.","chuHienThoi":"Lục Ma Châu","congNang":["Làm trung tâm tập kết và chỉ huy của lực lượng Lục Ma Châu trong Đan Hải @c1747"],"chuSoHuu":[{"ten":"Lục Ma Châu","tuChuong":"@c1747","denChuong":"","cachCoDuoc":"Bố trí trong chiến dịch Đan Hải","trangThai":"đang sử dụng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1747","loai":"xuất hiện","importance":"normal","giaiDoan":"Trung tâm chiến dịch Đan Hải","text":"Ba đại kỳ được cắm sâu trong biển, xung quanh là mấy ngàn tu sĩ Lục Ma Châu và ba tu sĩ áo trắng chỉ huy.","anchor":"có ba cây đại kỳ cắm sâu trong lòng biến"}]},"nguon":["@c1747"]},{"id":"van-tinh-hoa-o-dich","name":"Vạn Tịnh Hóa Ô Dịch","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Dịch lỏng","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang có","blurb":"Vạn Tịnh Hóa Ô Dịch là dịch lỏng màu đen được Vương Lâm ngưng tụ từ nước biển sau khi thủy bổn nguyên đại thành. Nó có thể hóa thành hắc thủy công kích diện rộng và ăn mòn sinh cơ của mục tiêu.","detail":"Vạn Tịnh Hóa Ô Dịch xuất hiện trong Đan Hải sau khi thủy bổn nguyên của Vương Lâm đại thành (@c1749). Vương Lâm vuốt giọt dịch khiến nó hóa thành hắc thủy lan rộng, tiêu diệt nhiều hư ảnh tu sĩ bằng cách ăn mòn, tuyệt khí, thân nát và khô héo.","phanLoaiPhu":"dịch lỏng màu đen","hinhDang":"một giọt nước màu đen","congNang":["Hóa thành hắc thủy công kích diện rộng @c1749","Ăn mòn và dập tắt sinh cơ của mục tiêu @c1749"],"dacDiem":"Hắc thủy có sức công phá mạnh, khiến tu sĩ bị ăn mòn hoặc mất sinh cơ.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1749","denChuong":"","cachCoDuoc":"ngưng tụ khi thủy bổn nguyên đại thành","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1749","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ trong Đan Hải","text":"Vương Lâm ngưng tụ Vạn Tịnh Hóa Ô Dịch từ nước biển sau khi thủy bổn nguyên đại thành và dùng nó hóa thành hắc thủy diệt hư ảnh tu sĩ.","anchor":"hóa thành một giọt nước màu đen. Chất lỏng này chính là Vạn Tịnh Hóa Ô Dịch"}]},"capNhatToi":"@c1749","nguon":["@c1749"]},{"id":"la-ban-tran-phap-dan-hai","name":"La bàn trận pháp Đan Hải","cn":"","aliases":["La bàn điều khiển cấm chế Đan Hải","La bàn của nữ tử trung niên Lục Ma Châu","La bàn của nữ tử","La bàn của nữ tử cầm la bàn"],"category":"phap-bao","categoryLabel":"Pháp bảo điều khiển","phamCap":"không rõ","soHuu":["Nữ tử cầm la bàn"],"trangThai":"đang dùng","blurb":"La bàn then chốt của cấm chế bao phủ Đan Hải. Nữ tử cầm la bàn dùng nó quan sát điểm sáng tu sĩ và truyền lệnh cho Lục Ma vệ.","detail":"La bàn này không phải vật phàm mà là vật then chốt của cấm chế Đan Hải. Khi điểm sáng quanh Vương Lâm tắt đi, nữ tử phun máu vào la bàn để mệnh lệnh truy sát truyền khắp Đan Hải.","phanLoaiPhu":"pháp bảo điều khiển cấm chế","congNang":["Quan sát điểm sáng tu sĩ trong Đan Hải @c1749","Truyền mệnh lệnh tới toàn bộ Lục Ma vệ trong Đan Hải @c1749"],"dacDiem":"Là vật then chốt của cấm chế bao phủ cả Đan Hải.","chuHienThoi":"Nữ tử cầm la bàn","chuSoHuu":[{"ten":"Nữ tử cầm la bàn","tuChuong":"@c1749","denChuong":"","cachCoDuoc":"đang nắm giữ dưới ba cây đại kỳ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1749","loai":"dùng","importance":"normal","giaiDoan":"Truy sát trong Đan Hải","text":"Nữ tử cầm la bàn dùng vật then chốt của cấm chế Đan Hải để truyền lệnh cho toàn bộ Lục Ma vệ truy sát Vương Lâm.","anchor":"La bàn này không phải là vật phàm, chính là vật then chốt của cấm chế bao phủ cả Đan Hải"}]},"capNhatToi":"@c1749","nguon":["@c1749"]},{"id":"cay-quat-van-ma-bon-dang-cua-thanh-nien-mat-trang","name":"Cây quạt vạn mã bôn đằng của thanh niên mặt trắng","aliases":["Cây quạt của thanh niên mặt trắng"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thanh niên mặt trắng"],"trangThai":"đang do Thanh niên mặt trắng sử dụng","blurb":"Pháp bảo hình quạt của thanh niên mặt trắng, mặt trước vẽ cảnh vạn mã bôn đằng.","detail":"Khi bị bàn tay hư ảo của Vương Lâm chụp tới, thanh niên mặt trắng mở quạt, gọi ra vô số ngựa hư ảo lao tới va chạm khiến cánh tay hư ảo tiêu tán, nhờ đó trốn vào trận pháp.","hinhDang":"cây quạt","congNang":["Triệu ra vô số ngựa hư ảo để phòng ngự và phản kích @c1750"],"chuSoHuu":[{"ten":"Thanh niên mặt trắng","tuChuong":"@c1750","denChuong":"","cachCoDuoc":"đang mang theo","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1750","loai":"dùng","importance":"normal","giaiDoan":"Phá bàn tay hư ảo","text":"Thanh niên mặt trắng mở quạt gọi vạn mã hư ảo để chống lại bàn tay hư ảo của Vương Lâm và trốn vào trận pháp.","anchor":"Mặt trước cây quạt này là một bước tranh vẻ vạn mã bôn đẳng"}]},"capNhatToi":"@c1750","nguon":["@c1750"]},{"id":"dan-hai-tien-dan","name":"Đan Hải tiên đan","aliases":["Nửa hạt tiên đan","Nửa viên tiên đan trong truyền thuyết","Một nửa hạt tiên đan do luyện hóa Đan Hải"],"cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Lục Ma Châu"],"trangThai":"dự định luyện hóa","blurb":"Nửa hạt tiên đan mà Lục Ma Châu dự định luyện hóa từ Đan Hải.","detail":"Nữ tử cầm la bàn nói Vân Không sẽ luyện hóa Đan Hải thành một nửa hạt tiên đan, dùng nó để nổ tung màn chắn Thiên Ngưu Châu, mở đường cho đại quân liên minh tam tông xuất động.","nguonGoc":"dự định luyện hóa từ Đan Hải","congNang":["Dùng để nổ tung màn chắn Thiên Ngưu Châu @c1750"],"tabs":{"tienTrinh":[{"chuong":"@c1750","loai":"nhắc tới","importance":"normal","giaiDoan":"Kế hoạch luyện hóa","text":"Nữ tử cầm la bàn nói Vân Không cần luyện hóa Đan Hải thành nửa hạt tiên đan để phá màn chắn Thiên Ngưu Châu.","anchor":"luyện hóa Đan Hải này, hóa thành một nửa hạt tiên đan"}]},"capNhatToi":"@c1750","nguon":["@c1750"]},{"id":"la-ban-hu-ao-tren-dan-hai","name":"La bàn hư ảo trên Đan Hải","cn":"","category":"phap-bao","categoryLabel":"Trận khí hư ảnh","phamCap":"không rõ","soHuu":[],"trangThai":"hư ảnh","blurb":"La bàn hư ảo trên Đan Hải nằm phía trên bảy tầng sương mù cấm chế và thong thả xoay tròn.","detail":"La bàn này tỏa uy áp dung hợp với sương mù của đại trận, nhưng chương nói rõ nó chỉ là hư ảo chứ không phải vật thật.","phanLoaiPhu":"trận khí hư ảnh","hinhDang":"la bàn xoay chậm trên bầu trời Đan Hải","dacDiem":"Là hư ảnh, không phải vật thật.","congNang":["Liên kết với bảy tầng sương mù cấm chế và tỏa uy áp dung hợp với đại trận Đan Hải."],"tabs":{"tienTrinh":[{"chuong":"@c1751","loai":"xuất hiện","importance":"normal","giaiDoan":"Trung tâm cấm chế","text":"La bàn hư ảo hiện phía trên bảy tầng sương mù Đan Hải, tỏa uy áp dung hợp với đại trận.","anchor":"Trên bảy tầng sương mù là một chiếc lan bàn."}]},"capNhatToi":"@c1751","nguon":["@c1751"]},{"id":"truong-kiem-bay-thuoc-cua-van-khong","name":"Trường kiếm bảy thước của Vân Không","cn":"","category":"phap-bao","categoryLabel":"Kiếm","phamCap":"không rõ","soHuu":["Vân Không"],"trangThai":"đang dùng","blurb":"Trường kiếm bảy thước của Vân Không xuất hiện khi kiếm ảnh hóa thành thanh y tu sĩ tại Đan Hải.","detail":"Thanh kiếm dài bảy thước, mặt kiếm như có dòng chảy chuyển động và lấp lánh hàn quang trong bóng đêm, được Vân Không cầm khi ngăn Vương Lâm rời đi.","phanLoaiPhu":"kiếm","hinhDang":"trường kiếm bảy thước lấp lánh hàn quang","chuHienThoi":"Vân Không","dacDiem":"Mặt kiếm như có dòng chảy chuyển động trong bóng đêm.","chuSoHuu":[{"ten":"Vân Không","tuChuong":"@c1751","denChuong":"","cachCoDuoc":"đã cầm khi kiếm ý phân thân hiện thân","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1751","loai":"xuất hiện","importance":"normal","giaiDoan":"Vân Không hiện thân","text":"Vân Không cầm trường kiếm bảy thước khi kiếm ảnh hóa thành thanh y tu sĩ và truy kích Vương Lâm.","anchor":"Trong tay hắn đang cầm một thanh trường kiếm bảy thước"}]},"capNhatToi":"@c1751","nguon":["@c1751"]},{"id":"truyen-am-phu-cua-dai-hon-mon","name":"Truyền Âm Phù của Đại Hồn Môn","cn":"","category":"khac","categoryLabel":"Truyền tin","phamCap":"chưa rõ","soHuu":["Vương Lâm","Đại Hồn Môn"],"trangThai":"đã dùng @c1752","blurb":"Truyền Âm Phù của Đại Hồn Môn được Vương Lâm dùng sau khi thoát Đan Hải. Hắn lưu một đạo thần niệm rồi vung phù lên trời để báo tin về Đại Hồn Môn.","detail":"Vương Lâm lấy Truyền Âm Phù của Đại Hồn Môn ra ngoài Đan Hải để truyền tin. Vật này có tốc độ nhanh hơn tu sĩ rất nhiều nhờ kết cấu đặc thù, thích hợp dùng khi cần báo tin khẩn cấp.","phanLoaiPhu":"Truyền tin","congNang":["Truyền âm tốc độ cao nhờ kết cấu đặc thù @c1752"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1752","denChuong":"","cachCoDuoc":"Có từ thân phận trưởng lão Đại Hồn Môn","trangThai":"đã dùng để báo tin"}],"tabs":{"tienTrinh":[{"chuong":"@c1752","loai":"dùng","importance":"normal","giaiDoan":"Báo tin Đại Hồn Môn","text":"Vương Lâm lấy Truyền Âm Phù của Đại Hồn Môn, lưu thần niệm rồi vung lên trời để báo tin sau khi thoát Đan Hải.","anchor":"Đây là Truyền Âm Phù của Đại Hồn Môn."}]},"dinhDanh":"goc","capNhatToi":"@c1752","nguon":["@c1752"]},{"id":"ho-lo-chua-ba-nghin-van-dao-hon","name":"Hồ lô chứa ba nghìn vạn đạo hồn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"đã cho nổ đạo hồn","blurb":"Hồ lô chứa ba nghìn vạn đạo hồn là một trong các pháp bảo Vương Lâm thắng được từ Viêm Loan sau khi xóa thần thức đối thủ. Bên trong chứa hơn ba nghìn vạn đạo hồn, uy lực bộc phát rất mạnh nhưng chỉ có duy nhất một cơ hội sử dụng. Về sau được Vương Lâm dùng để mở con đường máu, che giấu khôi lỗi và cho nổ uy hiếp tu sĩ Không Kiếp.","detail":"Vương Lâm nhắc tới hồ lô này khi điểm lại các pháp bảo thắng từ Viêm Loan lúc quyết định quay lại Đan Hải, nhấn mạnh nó có uy lực bộc phát mạnh nhưng chỉ dùng được một lần (@c1752). Bên trong hồ lô chứa hơn ba nghìn vạn đạo hồn (@c1763). Vương Lâm từng dùng nó cùng máu huyết để mở con đường máu, triệu anh hồn tổ tiên và thi triển Hồn huyễn trở về (@c1763); đưa hồ lô vào mặt đất Không Gian Thạch, tỏa tử khí từ đạo hồn để che giấu hơi thở khôi lỗi Dĩ Ti trong sát trận (@c1769). Cao trào là khi Vương Lâm cho nổ gần ba ngàn vạn đạo hồn trong hồ lô, buộc Trương Đạo Tông và Lục Ma sứ giả chậm lại — đủ sức uy hiếp tu sĩ Không Kiếp trung kỳ (@c1774).","phanLoaiPhu":"Hồ lô pháp bảo","uyLuc":"Khi cho nổ gần ba ngàn vạn đạo hồn, đủ sức buộc Trương Đạo Tông và Lục Ma sứ giả chậm lại và uy hiếp tu sĩ Không Kiếp trung kỳ.","dacDiem":"Chứa hơn ba nghìn vạn đạo hồn, bộc phát cực mạnh nhưng chỉ có một cơ hội sử dụng.","congNang":["Bộc phát uy lực rất mạnh nhưng chỉ dùng được một lần @c1752","Chứa hơn ba nghìn vạn đạo hồn @c1763","Hỗ trợ mở con đường máu để triệu anh hồn tổ tiên và thi triển Hồn huyễn trở về @c1763","Tỏa tử khí từ đạo hồn để che giấu hơi thở khôi lỗi Dĩ Ti trong sát trận @c1769","Cho nổ gần ba ngàn vạn đạo hồn để uy hiếp tu sĩ Không Kiếp trung kỳ @c1774"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1752","denChuong":"","cachCoDuoc":"Đã có trong tay trước lúc bị truy sát","trangThai":"đã dùng để phá vây"}],"tabs":{"tienTrinh":[{"chuong":"@c1752","loai":"nhắc tới","importance":"normal","giaiDoan":"Chuẩn bị quay lại Đan Hải","text":"Hồ lô chứa ba nghìn vạn đạo hồn được nhắc là pháp bảo thắng từ Viêm Loan, có uy lực bộc phát mạnh nhưng chỉ dùng được một lần.","anchor":"Nhất là hồ lô chứa ba nghìn vạn đạo hồn"},{"chuong":"@c1763","loai":"dùng","importance":"normal","giaiDoan":"Mở con đường máu","text":"Vương Lâm dùng hồ lô chứa đạo hồn cùng máu huyết để mở con đường máu và thi triển Hồn huyễn trở về.","anchor":"Trong hồ lô nọ ẩn chứa hơn ba nghìn vạn đạo hồn"},{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Tử khí mặt đất","text":"Hồ lô đạo hồn được đưa vào mặt đất Không Gian Thạch, tỏa tử khí để che giấu Dĩ Ti trong sát trận.","anchor":"Hồ lô ẩn chứa ba nghìn vạn đạo hồn bị Vương Lâm lấy ra"},{"chuong":"@c1774","loai":"dùng","importance":"major","giaiDoan":"Nổ đạo hồn thoát thân","text":"Vương Lâm cho nổ gần ba ngàn vạn đạo hồn trong hồ lô, buộc Trương Đạo Tông và Lục Ma sứ giả chậm lại để hắn kịp chui vào đại địa.","anchor":"gần ba ngàn vạn đạo hồn bên trong hồ lô"}]},"dinhDanh":"goc","capNhatToi":"@c1752","nguon":["@c1752","@c1763","@c1769","@c1774"],"aliases":["Hồ lô hơn ba nghìn vạn đạo hồn","Hồ lô ba nghìn vạn đạo hồn","Hồ lô khổng lồ chứa Đạo Hồn"]},{"id":"trong-lon-den-kit-cua-luc-ma-chau","name":"Trống lớn đen kịt của Lục Ma Châu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo chiến tranh","phamCap":"không rõ","soHuu":["Lục Ma Châu"],"trangThai":"đang dùng","blurb":"Pháp bảo chiến tranh khổng lồ của Lục Ma Châu, thân trống đen kịt và có vô số oan hồn vờn quanh. Bên trong trống có tu sĩ ẩn nấp, giống như dung hợp với pháp bảo để dò xét bên ngoài.","detail":"Nhiều chiếc trống lớn gần trăm trượng được Lục Ma Châu hộ tống ra chiến trường quanh Đan Hải. Bên ngoài trống có vô số oan hồn, bên trong có tu sĩ dung hợp với trống và dùng thần thức quét qua khu vực xung quanh.","phanLoaiPhu":"pháp bảo chiến tranh","hinhDang":"Trống lớn gần trăm trượng, thân trống đen kịt","congNang":["Mang theo vô số oan hồn vờn quanh thân trống và có tu sĩ dung hợp bên trong để dùng thần thức dò xét @c1753"],"dacDiem":"Có tu sĩ ẩn bên trong như dung hợp với trống, khiến pháp bảo chiến tranh này có năng lực dò xét chủ động.","chuSoHuu":[{"ten":"Lục Ma Châu","tuChuong":"@c1753","denChuong":"","cachCoDuoc":"Được lực lượng Lục Ma Châu hộ tống ra chiến trường quanh Đan Hải","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1753","loai":"xuất hiện","importance":"normal","giaiDoan":"Pháp bảo chiến tranh quanh Đan Hải","text":"Trống lớn đen kịt của Lục Ma Châu xuất hiện giữa đội hình hộ tống, bên ngoài có oan hồn vờn quanh và bên trong có tu sĩ dung hợp để dò xét.","anchor":"Bên ngoài cái trống này tồn tại vô số oan hồn, vờn quanh chiếc trống"}]},"capNhatToi":"@c1753","nguon":["@c1753"]},{"id":"tien-dan-dan-hai","name":"Tiên đan Đan Hải","cn":"","aliases":["Đan Hải"],"category":"dan-duoc","categoryLabel":"Tiên đan","phamCap":"không rõ","soHuu":["Vân Không"],"trangThai":"nổ sớm @c1755","blurb":"Tiên đan Đan Hải là bản thể được hé lộ của Đan Hải, vốn do một viên tiên đan biến thành. Sau khi Vân Không dùng vật dẫn màu vàng ngưng tụ, nó bị Vương Lâm chém vào lúc bất ổn và nổ sớm giữa Đan Hải, gieo họa cho cả Thiên Ngưu Châu lẫn Lục Ma Châu.","detail":"Đan Hải được xác nhận là do một viên tiên đan biến thành, trở thành trung tâm kế hoạch công kích Thiên Ngưu Châu. Vân Không dùng giọt chất lỏng màu vàng làm vật dẫn để ép nước biển vượt cực hạn ngưng tụ tiên đan, nhưng Vương Lâm chém vào dòng xoáy khi tiên đan chưa ổn định, khiến nó nổ sớm. Vụ nổ tạo ra lực hủy diệt tác động lên cả Thiên Ngưu Châu lẫn Lục Ma Châu.","phanLoaiPhu":"tiên đan hóa thành vùng biển","chuHienThoi":"Vân Không","congNang":["Khi bị ngưng tụ và kích nổ có thể tạo lực hủy diệt cấp châu vực @c1755"],"tabs":{"tienTrinh":[{"chuong":"@c1755","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ bản thể Đan Hải","text":"Đan Hải được hé lộ là do tiên đan biến thành và trở thành trung tâm kế hoạch công kích Thiên Ngưu Châu.","anchor":"Đan Hải là do tiên đan biến thành"},{"chuong":"@c1755","loai":"dùng","importance":"major","giaiDoan":"Nổ sớm giữa Đan Hải","text":"Tiên đan bị Vương Lâm chém vào lúc bất ổn nên nổ sớm giữa Đan Hải, khiến cả hai châu đều chịu họa.","anchor":"Nhưng giờ phút này tiên đan lại nổ tung giữa Đan Hải"}]},"nguon":["@c1755"],"uyLuc":"Khi nổ sớm giữa Đan Hải, tạo lực hủy diệt tác động lên cả Thiên Ngưu Châu lẫn Lục Ma Châu @c1755","dacDiem":"Do một viên tiên đan biến thành, cần vật dẫn màu vàng ép nước biển vượt cực hạn để ngưng tụ @c1755"},{"id":"la-ban-co-kinh","name":"La bàn cổ kính","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo cấm chế","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ @c1756","blurb":"La bàn cổ kính do Vương Lâm thu được sau biến cố Đan Hải. Trên la bàn có bản đồ thay đổi theo khu vực và kèm cấm chế che giấu huyền diệu.","detail":"Sau vụ nổ, phần bản đồ Đan Hải trên la bàn biến mất, thay bằng vùng đất Thiên Ngưu Châu. Vương Lâm nhận ra cấm chế che giấu trên la bàn có thể tăng cường cấm chế bổn nguyên, nhưng tạm giữ lại vì còn cần dùng để che giấu tung tích.","phanLoaiPhu":"cấm chế vật","hinhDang":"la bàn cổ kính","chuHienThoi":"Vương Lâm","congNang":["Hiển thị bản đồ khu vực, sau vụ nổ Đan Hải chuyển sang vùng Thiên Ngưu Châu @c1756","Mang cấm chế che giấu để Vương Lâm che vùng chữa thương @c1756"],"dacDiem":"Có cấm chế che giấu huyền diệu, được Vương Lâm đánh giá là còn tác dụng lớn.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1756","denChuong":"","cachCoDuoc":"thu được trước khi chỉnh sửa ngọc giản ghi công","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1756","loai":"xuất hiện","importance":"normal","giaiDoan":"kiểm tra sau Đan Hải","text":"Vương Lâm lấy la bàn cổ kính ra kiểm tra, thấy bản đồ Đan Hải đã biến mất và quyết định giữ lại cấm chế che giấu vì còn hữu dụng.","anchor":"Chỉ thấy trong lòng bàn tay hắn xuất hiện thêm một chiếc la bàn"}]},"dinhDanh":"goc","capNhatToi":"@c1756","nguon":["@c1756"]},{"id":"ngoc-gian-ghi-canh-chem-tien-dan","name":"Ngọc giản ghi cảnh chém tiên đan","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"Tầm thường","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ @c1756","blurb":"Ngọc giản ghi lại quá trình Vương Lâm lần thứ hai tiến vào Đan Hải và chém tiên đan. Hắn chỉnh sửa nội dung, xóa đoạn lấy la bàn để dùng làm chứng cứ đổi công pháp.","detail":"Ngọc giản lưu cảnh Vương Lâm giết người, phá ba đại kỳ, chém tiên đan khiến Vân Không tử vong trong phân thân. Vương Lâm xóa đi đoạn bản thân lấy được la bàn, giữ phần còn lại để đòi tầng thứ chín Đa Trọng Huyễn Thuật.","phanLoaiPhu":"vật lưu ảnh chứng cứ","chuHienThoi":"Vương Lâm","congNang":["Ghi lại hình ảnh làm chứng cứ công lao chém tiên đan ở Đan Hải @c1756"],"dacDiem":"Bản thân ngọc giản tầm thường nhưng nội dung bên trong có giá trị làm chứng cứ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1756","denChuong":"","cachCoDuoc":"tự dùng để ghi lại quá trình tiến vào Đan Hải lần hai","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1756","loai":"xuất hiện","importance":"normal","giaiDoan":"chỉnh sửa chứng cứ","text":"Vương Lâm kiểm tra ngọc giản ghi cảnh chém tiên đan, xóa đoạn lấy la bàn và giữ lại phần chứng cứ công lao.","anchor":"Ngọc giản này rất tầm thường như bên trong lại ghi chép lần thứ hai Vương Lâm tiến vào Đan Hải"}]},"dinhDanh":"goc","capNhatToi":"@c1756","nguon":["@c1756"]},{"id":"hac-giay-mau-den","name":"Hạc giấy màu đen","cn":"","aliases":[],"category":"khac","categoryLabel":"Truyền tin vật","phamCap":"Không rõ","soHuu":["Đại Hồn Môn","Quy Nhất Tông"],"trangThai":"đang truyền Hồn Nhất Lệnh @c1756","blurb":"Hạc giấy màu đen là vật truyền tin bay khắp nơi sau khi Hồn Nhất Lệnh được phát ra. Vương Lâm bắt một con để nghe lệnh chiến của Đại Hồn Môn và Quy Nhất Tông.","detail":"Những hạc giấy mang u quang truyền đi tin Lục Ma Châu xâm lấn và lệnh triệu tập các tông môn phong bế sơn môn, chuẩn bị chiến đấu. Một con bị Vương Lâm dùng Định Thân Thuật giữ lại để đưa thần thức vào đọc tin.","phanLoaiPhu":"truyền lệnh vật","congNang":["Truyền Hồn Nhất Lệnh tới các tông môn Thiên Ngưu Châu @c1756"],"tabs":{"tienTrinh":[{"chuong":"@c1756","loai":"dùng","importance":"normal","giaiDoan":"truyền lệnh chiến tranh","text":"Hạc giấy màu đen bay đi truyền Hồn Nhất Lệnh, một con bị Vương Lâm bắt lại để đọc nội dung lệnh chiến.","anchor":"Chỉ thấy thiên địa phía trước lóe lên u quang, u quang nọ là mấy con hạc giấy màu đen"}]},"dinhDanh":"goc","capNhatToi":"@c1756","nguon":["@c1756"]},{"id":"hon-nhat-lenh","name":"Hồn Nhất Lệnh","cn":"","aliases":[],"category":"khac","categoryLabel":"Lệnh hiệu chiến tranh","phamCap":"Không rõ","soHuu":["Đại Hồn Môn","Quy Nhất Tông"],"trangThai":"đã phát ra @c1756","blurb":"Hồn Nhất Lệnh là lệnh chiến do Đại Hồn Môn và Quy Nhất Tông phát ra khi Lục Ma Châu xâm lấn. Lệnh này triệu tập các tông môn Thiên Ngưu Châu vào trạng thái phòng thủ chiến tranh, phong bế sơn môn và chuẩn bị chiến đấu.","detail":"Sau khi Đan Hải biến mất và đại quân Lục Ma Châu tiến vào, Đại Hồn Môn cùng Quy Nhất Tông phát Hồn Nhất Lệnh @c1756. Nội dung lệnh được truyền bằng hạc giấy màu đen, báo tin chiến tranh toàn châu đã mở ra, kêu gọi tất cả tông môn Thiên Ngưu Châu ứng phó cuộc xâm lấn.","phanLoaiPhu":"lệnh triệu tập phòng thủ","nguonGoc":"Đại Hồn Môn và Quy Nhất Tông phát ra","congNang":["Triệu tập tất cả tông môn Thiên Ngưu Châu ứng phó Lục Ma Châu xâm lấn @c1756","Ra lệnh phong bế sơn môn và chuẩn bị chiến đấu @c1756"],"uyLuc":"Có hiệu lực triệu tập các tông môn trong Thiên Ngưu Châu vào trạng thái phòng thủ chiến tranh.","tabs":{"tienTrinh":[{"chuong":"@c1756","loai":"xuất hiện","importance":"major","giaiDoan":"phát lệnh chiến tranh","text":"Đại Hồn Môn và Quy Nhất Tông phát Hồn Nhất Lệnh, triệu tập các tông môn phong bế sơn môn và chuẩn bị chiến đấu trước cuộc xâm lấn của Lục Ma Châu.","anchor":"Đại Hồn Môn, Quy Nhất Tông phát ra Hồn Nhất Lệnh, triệu tập tất cả tông môn"}]},"dinhDanh":"goc","capNhatToi":"@c1756","nguon":["@c1756"],"dacDiem":"Lệnh được truyền bằng hạc giấy màu đen."},{"id":"co-kiem-mau-vang-cua-van-khong","name":"Cổ kiếm màu vàng của Vân Không","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"Không rõ","soHuu":["Vân Không"],"trangThai":"Vân Không đang dùng @c1756","blurb":"Cổ kiếm màu vàng là pháp bảo mà bổn tôn Vân Không ngồi lên khi xuất hiện sau biến cố Đan Hải. Thanh kiếm tỏa kiếm ý ngập trời và khí tức cao quý.","detail":"Trên cổ kiếm màu vàng có Vân Không bổn tôn khoanh chân ngồi. Sau kiếm mơ hồ hiện ra thân ảnh mặc hoàng kim giáp, khiến khí thế của Vân Không càng thêm nổi bật trong đoàn quân Lục Ma Châu.","phanLoaiPhu":"phi kiếm","hinhDang":"cổ kiếm màu vàng","chuHienThoi":"Vân Không","congNang":["Chở bổn tôn Vân Không xuất hiện trong chiến dịch tiến vào Thiên Ngưu Châu @c1756"],"dacDiem":"Kiếm ý ngập trời, có khí tức cao quý và bóng dáng hoàng kim giáp mơ hồ phía sau.","chuSoHuu":[{"ten":"Vân Không","tuChuong":"@c1756","denChuong":"","cachCoDuoc":"đang sở hữu khi bổn tôn xuất hiện","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1756","loai":"xuất hiện","importance":"normal","giaiDoan":"bổn tôn Vân Không hiện thân","text":"Bổn tôn Vân Không ngồi trên cổ kiếm màu vàng tỏa kiếm ý ngập trời khi tiến vào chiến cuộc sau vụ nổ Đan Hải.","anchor":"Đây là một thanh cổ kiếm màu vàng. Trên kiếm này có một thanh niên mặc thanh sam đang khoanh chân ngồi"}]},"dinhDanh":"goc","capNhatToi":"@c1756","nguon":["@c1756"]},{"id":"con-hac-giay-u-quang","name":"Con hạc giấy u quang","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm tín vật","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã xuất hiện","blurb":"Con hạc giấy tỏa u quang khiến Vương Lâm liên tưởng sâu hơn về chiến sự Lục Ma Châu - Thiên Ngưu Châu. Nó trở thành một manh mối gợi suy đoán chiến tranh cấp châu.","detail":"Sau khi chứng kiến con hạc giấy u quang, Vương Lâm nhận ra việc luyện hóa Đan Hải, phá màn chắn và xâm lấn Thiên Ngưu Châu không chỉ là ân oán tông môn. Vật này gắn với bước chuyển trong nhận thức của hắn về bản chất chiến sự.","congNang":["Gợi cho Vương Lâm suy đoán về bản chất sâu hơn của chiến tranh giữa Lục Ma Châu và Thiên Ngưu Châu @c1757"],"tabs":{"tienTrinh":[{"chuong":"@c1757","loai":"nhắc tới","importance":"normal","giaiDoan":"Gợi suy đoán chiến sự","text":"Con hạc giấy u quang là dấu hiệu khiến Vương Lâm suy nghĩ rằng chiến sự đã vượt khỏi ân oán tông môn.","anchor":"Đó là sau khi chứng kiến con hạc giấy tòa u quang này"}]},"nguon":["@c1757"]},{"id":"nguoi-ti-hon-trong-long-ban-tay-vuong-lam","name":"Người tí hon trong lòng bàn tay Vương Lâm","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật dẫn tính toán","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã xuất hiện","blurb":"Người tí hon xuất hiện trong lòng bàn tay Vương Lâm khi hắn cân nhắc tính toán biến hóa thiên địa. Hắn cuối cùng không tiếp tục thôi diễn mà thu lại.","detail":"Vương Lâm lấy người tí hon ra trong lúc suy nghĩ về chiến sự và ba lễ vật Đại Hồn Môn, nhưng cho rằng đạo thuật của mình không đủ tính ra chân tướng nên nắm tay thu lại. Vật này liên hệ với hành động tính toán thiên địa của hắn.","congNang":["Liên quan đến việc Vương Lâm tính toán biến hóa thiên địa @c1757"],"tabs":{"tienTrinh":[{"chuong":"@c1757","loai":"xuất hiện","importance":"normal","giaiDoan":"Dừng tính toán","text":"Vương Lâm lấy người tí hon ra rồi thu lại, quyết định không tiếp tục tính toán thiên địa.","anchor":"trong lòng bàn tay liền xuất hiện một người tí hon"}]},"nguon":["@c1757"]},{"id":"lenh-bai-than-phan-dai-hon-mon-cua-vuong-lam","name":"Lệnh bài thân phận Đại Hồn Môn của Vương Lâm","cn":"","aliases":[],"category":"khac","categoryLabel":"Lệnh bài","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Lệnh bài thân phận của Vương Lâm tại Đại Hồn Môn. Hắn dùng nó để phối hợp kiểm tra khi trở về tông môn giữa thời chiến.","detail":"Vương Lâm xuất ra lệnh bài từng dùng khi vào Tàng Hồn Các, để lại một đạo thần thức và một giọt máu tươi lên đó. Hộ môn đại trận dựa vào lệnh bài để xác minh thân phận và quét thân thể hắn trước khi cho vào tông môn.","congNang":["Xác minh thân phận qua thần thức và máu tươi khi trở về Đại Hồn Môn @c1757"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1757","denChuong":"","cachCoDuoc":"lệnh bài thân phận Đại Hồn Môn đã có từ trước khi vào Tàng Hồn Các","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1757","loai":"dùng","importance":"normal","giaiDoan":"Kiểm tra sơn môn","text":"Vương Lâm dùng lệnh bài thân phận, để lại thần thức và máu tươi để hộ môn đại trận kiểm tra.","anchor":"Vương Lâm để lại một đạo thần thức và một giọt máu tươi từ đầu ngón tay lên đó"}]},"nguon":["@c1757"]},{"id":"ngoc-gian-vuong-lam-giao-thanh-nguu-chan-nhan","name":"Ngọc giản Vương Lâm giao Thanh Ngưu chân nhân","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Thanh Ngưu chân nhân"],"trangThai":"đã giao","blurb":"Ngọc giản tình báo Vương Lâm giao cho Thanh Ngưu chân nhân. Nội dung của nó giúp Vương Lâm được xác nhận là lập đại công trong bối cảnh Lục Ma Châu luyện hóa Đan Hải.","detail":"Thanh Ngưu chân nhân nói đã nhận ngọc giản của Vương Lâm và coi đây là công lao lớn. Vật này gắn với thông tin quan trọng về cục diện Lục Ma Châu nhiều lần mạo phạm Thiên Ngưu Châu.","congNang":["Truyền tin hoặc tình báo khiến Thanh Ngưu chân nhân xác nhận Vương Lâm lập đại công @c1757"],"chuSoHuu":[{"ten":"Thanh Ngưu chân nhân","tuChuong":"@c1757","denChuong":"","cachCoDuoc":"nhận từ Vương Lâm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1757","loai":"nhắc tới","importance":"normal","giaiDoan":"Xác nhận công lao","text":"Thanh Ngưu chân nhân xác nhận đã thu ngọc giản của Vương Lâm và nói hắn lập đại công.","anchor":"Ngọc giản của ngươi ta đã thu rồi. Việc này ngươi đã lập được đại công!"}]},"nguon":["@c1757"]},{"id":"ngoc-gian-ghi-viec-vuong-lam-tram-tien-dan","name":"Ngọc giản ghi việc Vương Lâm trảm tiên đan","cn":"","category":"khac","categoryLabel":"Ngọc giản tình báo","phamCap":"Không rõ","soHuu":["Vương Lâm","Thanh Ngưu chân nhân"],"trangThai":"đã giao cho Thanh Ngưu chân nhân","blurb":"Ngọc giản ghi lại việc Vương Lâm trảm tiên đan tại Đan Hải, dùng để chứng minh công lao với Đại Hồn Môn.","detail":"Vương Lâm giao ngọc giản này cho Thanh Ngưu chân nhân. Sau khi xem xét thông tin lưu bên trong, Thanh Ngưu xác nhận công lao trảm tiên đan tại Đan Hải của hắn và đồng ý ban thưởng Đa Trọng Huyễn Thuật @c1758.","congNang":["Lưu giữ thông tin sự kiện trảm tiên đanở Đan Hải, dùng làm bằng chứng xác nhận công lao @c1758"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1758","denChuong":"@c1758","cachCoDuoc":"Mang theo làm chứng cứ công lao","trangThai":"đã giao"},{"ten":"Thanh Ngưu chân nhân","tuChuong":"@c1758","denChuong":"","cachCoDuoc":"Nhận từ Vương Lâm để xem xét công lao","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"đổi chủ","importance":"major","giaiDoan":"Chứng minh công lao","text":"Vương Lâm giao ngọc giản ghi việc trảm tiên đan cho Thanh Ngưu chân nhân, khiến công lao Đan Hải được xác nhận.","anchor":"Cho đến khi xem xét xong tất cả thông tin khi Vương Lâm trảm tiên đan"}]},"capNhatToi":"@c1758","nguon":["@c1758"]},{"id":"ngoc-gian-da-trong-huyen-thuat-tang-chin","name":"Ngọc giản Đa Trọng Huyễn Thuật tầng chín","cn":"","category":"khac","categoryLabel":"Ngọc giản công pháp","phamCap":"Không rõ","soHuu":["Thanh Ngưu chân nhân","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Ngọc giản truyền thừa chứa Đa Trọng Huyễn Thuật đầy đủ ở tầng chín Tàng Hồn Các cùng phương pháp luyện chế Quỷ Phàm. Đây là vật Thanh Ngưu chân nhân trao cho Vương Lâm để mở ra việc nghiên cứu Quỷ Phàm.","detail":"Thanh Ngưu chân nhân trao ngọc giản này cho Vương Lâm sau khi xác nhận công laoở Đan Hải @c1758. Bên trong ngọc giản ghi khẩu quyết Đa Trọng Huyễn Thuật tầng chín cùng phương pháp và yêu cầu luyện chế Quỷ Phàm, giúp Vương Lâm hiểu về Quỷ Phàm, tử hồn cùng nguyên lý quỷ ám và mở ra hướng nghiên cứu này.","congNang":["Truyền thừa khẩu quyết Đa Trọng Huyễn Thuật tầng chín @c1758","Ghi phương pháp và yêu cầu luyện chế Quỷ Phàm @c1758"],"chuSoHuu":[{"ten":"Thanh Ngưu chân nhân","tuChuong":"@c1758","denChuong":"@c1758","cachCoDuoc":"Nắm giữ truyền thừa tầng chín của Đại Hồn Môn","trangThai":"đã trao"},{"ten":"Vương Lâm","tuChuong":"@c1758","denChuong":"","cachCoDuoc":"Nhận từ Thanh Ngưu chân nhân sau khi lập công ở Đan Hải","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"đổi chủ","importance":"major","giaiDoan":"Trao truyền thừa","text":"Thanh Ngưu chân nhân trao ngọc giản Đa Trọng Huyễn Thuật tầng chín cho Vương Lâm, mở ra việc nghiên cứu Quỷ Phàm và tử hồn.","anchor":"Vương Lâm tiếp nhận lấy, bên trong đúng là một trong những khâu quyết thuật pháp cường đại"}]},"capNhatToi":"@c1758","nguon":["@c1758"]},{"id":"quy-pham","name":"Quỷ Phàm","aliases":["Tấm buồm mặt quỷ"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo huyễn thuật","phamCap":"Sơ phẩm, trung phẩm, thượng phẩm, cực phẩm, tuyệt phẩm","soHuu":["Đại Hồn Môn","Vương Lâm"],"trangThai":"dang-co","blurb":"Quỷ Phàm là pháp bảo tấm buồm mặt quỷ gắn liền với việc tu luyện và thi triển Đa Trọng Huyễn Thuật. Pháp bảo có năm phẩm cấp và cần tử hồn phù hợp để luyện chế.","detail":"Quỷ Phàm lần đầu lộ diện trong ngọc giản Đa Trọng Huyễn Thuật, hiện thân là tấm buồm mang mặt quỷ (@c1758). Đây là nền tảng để phối hợp Đa Trọng Huyễn Thuật, với phẩm chất chia thành năm cấp bậc; phẩm càng cao thì uy lực phối hợp thuật pháp càng đáng sợ, còn việc luyện chế đòi hỏi tử hồn phù hợp. Trong thiên địa sát trận của Không Gian Thạch, Quỷ Phàm bay lên và hóa thành tầng mây (@c1769).","phanLoaiPhu":"Tấm buồm mặt quỷ","hinhDang":"Tấm buồm mặt quỷ","congNang":["Phối hợp với Đa Trọng Huyễn Thuật để tạo huyễn thuật dựa trên tử hồn và oán khí @c1758","Hóa thành tầng mây trong sát trận @c1769","Có thể biến thành vạn vật @c1769"],"dacDiem":"Chia năm phẩm cấp, phẩm càng cao uy lực phối hợp Đa Trọng Huyễn Thuật càng mạnh.","tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ tên và phẩm cấp","phamCap":"Sơ, trung, thượng, cực, tuyệt","text":"Ngọc giản Đa Trọng Huyễn Thuật lộ tấm buồm mặt quỷ tên là Quỷ Phàm, có năm phẩm cấp và cần tử hồn để luyện chế.","anchor":"tấm buồm mặt quỷ tên là Quỷ Phàm, phẩm chất chia làm năm cấp bậc"},{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Hóa mây trong trận","text":"Quỷ Phàm bay lên và hóa thành tầng mây trong thiên địa sát trận của Không Gian Thạch.","anchor":"Quỷ Phàm tự động bay lên, hóa thành một tầng mây trong thiên địa"}]},"capNhatToi":"@c1758","nguon":["@c1758","@c1769"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1769","denChuong":"","cachCoDuoc":"Do Vương Lâm chế tạo và sử dụng","trangThai":"dang-giu"}]},{"id":"tai-lieu-luyen-che-quy-pham","name":"Tài liệu luyện chế Quỷ Phàm","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khí","phamCap":"Phẩm chất tuyệt hảo","soHuu":["Thanh Ngưu chân nhân","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Nhiều tài liệu luyện khí trân quý do Thanh Ngưu chân nhân tặng Vương Lâm để luyện chế Quỷ Phàm.","detail":"Thanh Ngưu chân nhân lấy ra một vầng sáng chứa không ít tài liệu luyện khí phẩm chất tốt và giao cho Vương Lâm. Phần hồn phách dùng để luyện chế thì Vương Lâm phải tự chọn hoặc đến Quỷ Phong tìm kiếm.","congNang":["Dùng làm tài liệu luyện chế Quỷ Phàm @c1758"],"chuSoHuu":[{"ten":"Thanh Ngưu chân nhân","tuChuong":"@c1758","denChuong":"@c1758","cachCoDuoc":"Nắm giữ tài liệu luyện khí của Đại Hồn Môn","trangThai":"đã trao"},{"ten":"Vương Lâm","tuChuong":"@c1758","denChuong":"","cachCoDuoc":"Được Thanh Ngưu chân nhân tặng để luyện Quỷ Phàm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"đổi chủ","importance":"normal","giaiDoan":"Trao tài liệu","text":"Thanh Ngưu chân nhân trao nhiều tài liệu luyện khí phẩm chất tốt cho Vương Lâm để chuẩn bị luyện chế Quỷ Phàm.","anchor":"trong tay liền hiện ra một vầng sáng, bên trong đó tồn tại không ít tài liệu luyện khí"}]},"capNhatToi":"@c1758","nguon":["@c1758"]},{"id":"tam-buom-mat-quy-cua-phan-san-mong","name":"Tấm buồm mặt quỷ của Phàn San Mộng","cn":"","category":"phap-bao","categoryLabel":"Quỷ Phàm trung phẩm","phamCap":"Trung phẩm","soHuu":["Phàn San Mộng"],"trangThai":"Phàn San Mộng đang giữ","blurb":"Quỷ Phàm trung phẩm của Phàn San Mộng, do Viêm Loan tặng năm xưa.","detail":"Tấm buồm mặt quỷ này được nêu làm ví dụ cho Quỷ Phàm trung phẩm. Nó do Viêm Loan tặng Phàn San Mộng, có thể thi triển tốt dù người dùng không cần tu vi cao.","congNang":["Phối hợp huyễn thuật của Quỷ Phàm trung phẩm và có thể dùng tốt dù không cần tu vi cao @c1758"],"chuSoHuu":[{"ten":"Viêm Loan","tuChuong":"@c1758","denChuong":"@c1758","cachCoDuoc":"Từng sở hữu trước khi tặng","trangThai":"đã trao"},{"ten":"Phàn San Mộng","tuChuong":"@c1758","denChuong":"","cachCoDuoc":"Được Viêm Loan tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"nhắc tới","importance":"normal","giaiDoan":"Xác nhận phẩm cấp","phamCap":"Trung phẩm","text":"Tấm buồm mặt quỷ của Phàn San Mộng được xác nhận là Quỷ Phàm trung phẩm do Viêm Loan tặng.","anchor":"tấm buồm mặt quỷ của Phàn San Mộng năm đó chính là cấp trung do Viêm Loan tặng"}]},"capNhatToi":"@c1758","nguon":["@c1758"]},{"id":"ho-son-dai-tran-dai-hon-mon","name":"Hộ sơn đại trận Đại Hồn Môn","aliases":["Quỷ Phàm tuyệt phẩm"],"cn":"","category":"phap-bao","categoryLabel":"Trận pháp pháp bảo","phamCap":"Tuyệt phẩm","soHuu":["Đại Hồn Môn"],"trangThai":"đang trấn thủ Đại Hồn Môn","blurb":"Hộ sơn đại trận Đại Hồn Môn được xác nhận chính là tấm Quỷ Phàm tuyệt phẩm duy nhất được nhắc tới. Nó giữ vai trò trấn thủ, bảo hộ cho Đại Hồn Môn.","detail":"Hộ sơn đại trận của Đại Hồn Môn chính là tấm Quỷ Phàm tuyệt phẩm duy nhất được xác nhận trong tiến trình (@c1758). Vương Lâm từng thấy nó nhưng khi đó đại trận chưa triển khai hết uy lực cực hạn. Đại trận đảm nhận vai trò hộ sơn, trấn thủ cho Đại Hồn Môn.","congNang":["Làm hộ sơn đại trận trấn thủ Đại Hồn Môn @c1758"],"dacDiem":"Là Quỷ Phàm tuyệt phẩm duy nhất được nhắc tới trong chương.","tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"khai phong","importance":"major","giaiDoan":"Lộ bản chất Quỷ Phàm","phamCap":"Tuyệt phẩm","text":"Hộ sơn đại trận Đại Hồn Môn được xác nhận chính là tấm Quỷ Phàm tuyệt phẩm duy nhất.","anchor":"Tấm Quỷ Phàm này chính là hộ sơn đại trận của Đại Hồn Môn"}]},"capNhatToi":"@c1758","nguon":["@c1758"]},{"id":"quy-pham-trang-cua-vuong-lam","name":"Quỷ Phàm trắng của Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Sơ phẩm","soHuu":["Vương Lâm"],"trangThai":"Đã dung nhập tử hồn Côn Hư, có thể dùng làm vật dẫn thi triển Đa Trọng Huyễn Thuật","blurb":"Quỷ Phàm do Vương Lâm luyện theo ngọc giản Đa Trọng Huyễn Thuật, ban đầu là tấm buồm màu đen, sau khi dung nhập tử hồn Côn Hư thì chuyển thành màu trắng.","detail":"Trong năm ngày bế quan, Vương Lâm luyện hóa toàn bộ tài liệu luyện khí thành thân tấm buồm theo phương pháp trong ngọc giản Đa Trọng Huyễn Thuật. Vật này ban đầu chưa hoàn thiện vì thiếu tử hồn; sau khi hắn vào Quỷ Phong chọn nữ tử bạch y, đặt tên Côn Hư và thu nàng dung nhập, Quỷ Phàm đổi sang màu trắng, thỉnh thoảng truyền ra tiếng khóc thảm thiết khiến tâm thần người nghe hiện lên bóng lưng nữ tử đang khóc.","nguon":["@c1759"]},{"id":"ngoc-gian-lenh-tran-thu-de-tam-huyet","name":"Ngọc giản lệnh trấn thủ đệ tam huyệt","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Thanh Ngưu chân nhân","Vương Lâm"],"trangThai":"Đã truyền tới động phủ Vương Lâm vào hoàng hôn ngày thứ bảy","blurb":"Ngọc giản do Thanh Ngưu chân nhân truyền tới, lệnh Vương Lâm đi trấn thủ đệ tam huyệt của Thiên Ngưu.","detail":"Hoàng hôn ngày thứ bảy, ngọc giản xuyên qua cấm chế vào động phủ của Vương Lâm và truyền ra giọng Thanh Ngưu chân nhân. Ngoài mệnh lệnh tới đệ tam huyệt Thiên Ngưu trấn thủ, ngọc giản còn chứa thông tin về bảy Thiên Ngưu huyệt do các đời Đại Hồn Môn mở theo bảy tinh huyệt của Thiên Ngưu Châu, có thể mượn lực Thiên Ngưu hình thành trận pháp cấm chế cực mạnh.","nguon":["@c1759"]},{"id":"ngoc-gian-cua-thanh-nguu-lao-to","name":"Ngọc giản của Thanh Ngưu lão tổ","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản lệnh truyền","phamCap":"Không rõ","soHuu":["Thanh Ngưu chân nhân"],"trangThai":"đã phát ra","blurb":"Ngọc giản của Thanh Ngưu lão tổ là lệnh điều động gửi tới Vương Lâm và các trưởng lão Đại Hồn Môn.","detail":"Ngọc giản không chỉ chuyển tới Vương Lâm mà còn tới tổng cộng bốn vị trưởng lão trong Đại Hồn Môn, mở đầu việc điều động tới các điểm trấn thủ.","congNang":["Truyền lệnh điều động trưởng lão Đại Hồn Môn @c1760"],"chuSoHuu":[{"ten":"Thanh Ngưu chân nhân","tuChuong":"@c1760","denChuong":"","cachCoDuoc":"Người phát lệnh","trangThai":"chu-lenh"}],"tabs":{"tienTrinh":[{"chuong":"@c1760","loai":"xuất hiện","importance":"normal","giaiDoan":"Lệnh điều động","text":"Ngọc giản được gửi tới Vương Lâm và bốn trưởng lão Đại Hồn Môn để điều động trấn thủ.","anchor":"còn đưa tới tổng cộng bốn vị trưởng lão trong Đại Hồn Môn"}]},"capNhatToi":"@c1760","nguon":["@c1760"]},{"id":"hanh-dan","name":"Hành Đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược chí bảo","phamCap":"Chí bảo","soHuu":["Mạnh sư bá"],"trangThai":"đang ở trên tay Mạnh sư bá","blurb":"Hành Đan là chí bảo do lão tổ đời đầu Đại Hồn Môn để lại, được mô tả cực kỳ huyền diệu.","detail":"Hành Đan hiện ở trên tay Mạnh sư bá. Lữ Văn Nhiễm từng sử dụng nó để từ Đan Hải trở về với tốc độ cực nhanh.","nguonGoc":"Lão tổ đời đầu Đại Hồn Môn để lại","congNang":["Giúp Lữ Văn Nhiễm từ Đan Hải trở về cực nhanh @c1760"],"chuSoHuu":[{"ten":"Mạnh sư bá","tuChuong":"@c1760","denChuong":"","cachCoDuoc":"Đang giữ chí bảo của lão tổ","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1760","loai":"nhắc tới","importance":"normal","giaiDoan":"Chí bảo trở về","text":"Hành Đan được nhắc là chí bảo huyền diệu của lão tổ, đang ở trên tay Mạnh sư bá và từng giúp Lữ Văn Nhiễm trở về từ Đan Hải.","anchor":"Hành Đan nọ là chí bảo của lão tổ, cực kỳ huyền diệu"}]},"capNhatToi":"@c1760","nguon":["@c1760"]},{"id":"ngoc-gian-kich-hoat-truyen-tong-tran","name":"Ngọc giản kích hoạt truyền tống trận","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản tiêu hao","phamCap":"Quý hiếm","soHuu":["Lữ Văn Nhiễm"],"trangThai":"đã tiêu tán","blurb":"Ngọc giản do Lữ Văn Nhiễm dùng để xác định và kích hoạt truyền tống trận cổ tới gần Thiên Ngưu đệ tam huyệt.","detail":"Sau khi hoàn tất truyền tống, ngọc giản trong tay Lữ Văn Nhiễm hóa thành từng điểm sáng tiêu tán, cho thấy đây là vật tiêu hao quý hiếm.","congNang":["Xác định và kích hoạt truyền tống trận cổ của Đại Hồn Môn @c1760"],"dacDiem":"Vật tiêu hao, dùng xong hóa thành điểm sáng tiêu tán","chuSoHuu":[{"ten":"Lữ Văn Nhiễm","tuChuong":"@c1760","denChuong":"@c1760","cachCoDuoc":"Mang theo để kích hoạt truyền tống trận","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1760","loai":"dùng","importance":"normal","giaiDoan":"Kích hoạt truyền tống","text":"Lữ Văn Nhiễm dùng ngọc giản để kích hoạt truyền tống trận cổ, sau đó ngọc giản tiêu tán.","anchor":"Ngọc giản trong tay Lữ Văn Nhiễm hóa thành từng điểm sáng tiêu tán"}]},"capNhatToi":"@c1760","nguon":["@c1760"]},{"id":"la-ban-cam-che","name":"La bàn cấm chế","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo trận khí","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"La bàn dùng để dò xét cấm chế, được Vương Lâm sử dụng tại Cực Thiên thảo nguyên.","detail":"Vương Lâm dùng la bàn cấm chế để âm thầm thăm dò cấm chế Cực Thiên thảo nguyên mà Lữ Văn Nhiễm không phát hiện. Khi quân Lục Ma Châu tới, la bàn chấn động, hiện bản đồ Cực Thiên thảo nguyên và đường xanh ở biên giới.","phanLoaiPhu":"trận khí","chuHienThoi":"Vương Lâm","congNang":["Dò xét cấm chế Cực Thiên thảo nguyên.","Hiện bản đồ và báo dấu hiệu tu sĩ Lục Ma Châu xuất hiện ở biên giới."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1761","denChuong":"","cachCoDuoc":"đang mang theo","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"dùng","importance":"normal","giaiDoan":"Dò trận và báo địch","text":"Vương Lâm dùng la bàn cấm chế dò trận, sau đó la bàn chấn động và hiện dấu hiệu quân Lục Ma Châu tới.","anchor":"la bàn vốn đặt trước người đột nhiên chấn động"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"la-ban-chien-truong-cua-vuong-lam","name":"La bàn chiến trường của Vương Lâm","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"La bàn Vương Lâm dùng trong chiến trường sương mù tại Cực Thiên thảo nguyên. Nó hiển thị điểm trắng và điểm xanh tượng trưng cho biến hóa của hai phe.","detail":"Trên la bàn hiện đầy các điểm trắng điểm xanh, giúp Vương Lâm quan sát tình hình khi di chuyển trong sương mù và tìm khu vực Không Kiếp sơ kỳ đang giao chiến.","congNang":["Theo dõi biến hóa chiến trường bằng các điểm trắng điểm xanh @c1762"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1762","denChuong":"","cachCoDuoc":"Đang mang theo trong chiến trường","trangThai":"đang giữ"}],"capNhatToi":"@c1762","tabs":{"tienTrinh":[{"chuong":"@c1762","loai":"dùng","importance":"normal","giaiDoan":"Theo dõi chiến trường sương mù","text":"Vương Lâm dùng la bàn để quan sát các điểm trắng điểm xanh đại diện biến hóa trong chiến trường.","anchor":"Trên la bàn lúc này đầy những điểm trắng điểm xanh"}]},"nguon":["@c1762"]},{"id":"khoi-loi-di-ti","name":"Khôi lỗi Dĩ Ti","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khôi lỗi Dĩ Ti được Vương Lâm tính là một trong các thủ đoạn đối phó Không Kiếp sơ kỳ. Chương này chỉ nhắc tới khả năng tung một đòn nghiêm trọng, chưa trực tiếp xuất hiện chiến đấu.","detail":"Trong lúc cân nhắc kế hoạch giết Không Kiếp sơ kỳ, Vương Lâm xem khôi lỗi Dĩ Ti là một thủ đoạn có thể tạo đòn đánh nặng trước khi dùng các biện pháp khác kết liễu hoặc trọng thương mục tiêu.","congNang":["Có thể tung một đòn nghiêm trọng vào tu sĩ Không Kiếp sơ kỳ @c1762","Ẩn giấu trong mặt đất sát trận @c1769"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1762","denChuong":"","cachCoDuoc":"Khôi lỗi đang thuộc Vương Lâm","trangThai":"dang-giu"}],"capNhatToi":"@c1762","tabs":{"tienTrinh":[{"chuong":"@c1762","loai":"nhắc tới","importance":"normal","giaiDoan":"Kế hoạch phục kích Không Kiếp","text":"Vương Lâm cân nhắc khôi lỗi Dĩ Ti như một thủ đoạn có thể đánh nặng vào Không Kiếp sơ kỳ.","anchor":"Khôi lỗi Dĩ Ti có thể ra một đòn nghiêm trọng"},{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Ẩn trong mặt đất","text":"Khôi lỗi Dĩ Ti dung nhập vào mặt đất Không Gian Thạch và được tử khí đạo hồn che giấu hơi thở.","anchor":"Còn về khôi lỗi Dĩ Ti thì dung nhập vào mặt đất"}]},"nguon":["@c1762","@c1769"]},{"id":"qua-cau-anh-sang-lo-dinh-cua-luu-chi-nguyen","name":"Quả cầu ánh sáng lô đỉnh của Lưu Chi Nguyên","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Lưu Chi Nguyên"],"trangThai":"đang chuẩn bị bị cắn nuốt","blurb":"Hơn mười quả cầu ánh sáng Lưu Chi Nguyên lấy ra khi lui khỏi giao chiến. Mỗi quả chứa một nữ tử lô đỉnh, được hắn định cắn nuốt để bổ sung lực lượng.","detail":"Các quả cầu chứa nữ tử lõa thể khoanh chân với thần sắc thê lương. Chúng thể hiện cách Lưu Chi Nguyên dùng lô đỉnh làm nguồn bổ sung trong công pháp song tu hắc liên.","hinhDang":"Quả cầu ánh sáng chứa nữ tử lô đỉnh","dacDiem":"Mỗi quả cầu có một nữ tử bên trong, được dùng làm nguồn bị cắn nuốt.","congNang":["Bị Lưu Chi Nguyên cắn nuốt để bổ sung lực lượng @c1762"],"chuSoHuu":[{"ten":"Lưu Chi Nguyên","tuChuong":"@c1762","denChuong":"","cachCoDuoc":"Mang theo trong chiến trường","trangThai":"đang giữ"}],"capNhatToi":"@c1762","tabs":{"tienTrinh":[{"chuong":"@c1762","loai":"xuất hiện","importance":"normal","giaiDoan":"Lưu Chi Nguyên lui lại bổ sung","text":"Lưu Chi Nguyên lấy hơn mười quả cầu ánh sáng chứa nữ tử lô đỉnh và chuẩn bị cắn nuốt để bổ sung lực lượng.","anchor":"Bên trong mỗi quả cầu này có một nữ tử"}]},"nguon":["@c1762"]},{"id":"quang-cau-mau-den-cua-luu-chi-nguyen","name":"Quang cầu màu đen của Lưu Chi Nguyên","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chưa rõ","phamCap":"chưa rõ","soHuu":["Lưu Chi Nguyên"],"trangThai":"chưa dùng","blurb":"Quang cầu màu đen được Lưu Chi Nguyên lấy ra lúc tiên lực gần cạn và định cắn nuốt.","detail":"Khi bị khôi lỗi Dĩ Ti đả thương và tiên lực hao kiệt, Lưu Chi Nguyên lấy quang cầu màu đen ra định cắn nuốt để ứng phó nguy cơ, nhưng bị tấm buồm mặt quỷ màu trắng của Vương Lâm làm khựng lại.","congNang":["Được Lưu Chi Nguyên định cắn nuốt trong lúc nguy cấp, công năng cụ thể chưa rõ @c1763"],"chuSoHuu":[{"ten":"Lưu Chi Nguyên","tuChuong":"@c1763","denChuong":"","cachCoDuoc":"đã có trước khi giao chiến","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"xuất hiện","importance":"normal","giaiDoan":"Định cắn nuốt","text":"Lưu Chi Nguyên lấy quang cầu màu đen ra khi tiên lực gần cạn nhưng chưa kịp cắn nuốt.","anchor":"trong tay lập tức xuất hiện một quả cầu ánh sáng màu đen. Đang định cắn nuốt"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"chuong-mau-den-cua-luu-chi-nguyen","name":"Chuông màu đen của Lưu Chi Nguyên","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"chưa rõ","soHuu":["Lưu Chi Nguyên"],"trangThai":"đang sử dụng","blurb":"Pháp bảo chuông đen của Lưu Chi Nguyên, có thể triệu mấy chục vạn nữ oan hồn và tạo oán khí ngập trời.","detail":"Lưu Chi Nguyên lấy chuông đen ra khi bị Vương Lâm đánh tới tuyệt cảnh. Tiếng chuông hóa ra vô số hồn phách nữ tử bi thảm, oán khí lan khắp Cực Thiên thảo nguyên khiến nhiều tu sĩ Không Kiếp biến sắc.","congNang":["Triệu mấy chục vạn nữ oan hồn tạo oán khí ngập trời @c1763"],"uyLuc":"Oán khí từ chuông lan tới các chiến trường quanh Cực Thiên thảo nguyên và khiến nhiều tu sĩ Không Kiếp biến sắc.","chuSoHuu":[{"ten":"Lưu Chi Nguyên","tuChuong":"@c1763","denChuong":"","cachCoDuoc":"đã có trước trận phục kích","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"dùng","importance":"normal","giaiDoan":"Triệu nữ oan hồn","text":"Lưu Chi Nguyên dùng chuông đen triệu mấy chục vạn nữ oan hồn để phản kích Vương Lâm.","anchor":"Trong tay xuất hiện một cái chuông màu đen"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"truong-thuong-do-ruc-cua-hu-anh-la-van-hai","name":"Trường thương đỏ rực của hư ảnh La Vân Hải","cn":"","aliases":[],"category":"khac","categoryLabel":"Vũ khí do sát khí ngưng tụ","phamCap":"chưa rõ","soHuu":["La Vân Hải"],"trangThai":"tiêu tán theo hư ảnh","blurb":"Trường thương đỏ rực do hư ảnh La Vân Hải ngưng sát khí mà thành.","detail":"Sau khi được Vương Lâm triệu ra, hư ảnh La Vân Hải ngưng sát khí thành trường thương đỏ rực, ném đi phá tan thân ảnh nữ tử do hơn mười vạn oan hồn hợp thành.","hinhDang":"Trường thương đỏ rực","vatLieu":"Sát khí ngưng tụ","congNang":["Phá thân ảnh nữ tử do oan hồn kết tụ @c1763"],"chuSoHuu":[{"ten":"La Vân Hải","tuChuong":"@c1763","denChuong":"@c1763","cachCoDuoc":"do hư ảnh ngưng sát khí tạo thành","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"dùng","importance":"normal","giaiDoan":"Phá oan hồn","text":"Hư ảnh La Vân Hải dùng trường thương đỏ rực phá thân ảnh nữ tử do oan hồn hợp thành.","anchor":"hóa thành một thanh trường thương đỏ rực, bị hắn nắm trong tay"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"la-ban-doan-khong-cam","name":"La bàn Đoạn Không cấm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo cấm trận","phamCap":"không rõ","soHuu":["Cấm Ma Tông"],"trangThai":"biến mất, chưa bị hủy @c1764","blurb":"La bàn chứa hoặc liên quan Đoạn Không cấm của Cấm Ma Tông. Nó biến mất sau kịch biến Đan Hải nhưng dấu hiệu trong tông môn cho thấy chưa bị hủy, trở thành manh mối khiến Lục Ma Châu nghi Vương Lâm.","detail":"Lão già họ Triệu cho biết sau kịch biến Đan Hải, la bàn Đoạn Không cấm biến mất trên đường, nhưng trận pháp trong Cấm Ma Tông cho thấy vật này chưa bị hủy. Khi cấm chế che chiến trường bị nhận ra là Đoạn Không cấm trận, sự biến mất của la bàn trở thành đầu mối liên hệ tới Vương Lâm và cái chết của Lưu Chi Nguyên.","phanLoaiPhu":"cấm trận khí","nguonGoc":"Cấm Ma Tông","dacDiem":"Biến mất nhưng dấu hiệu trong tông môn cho thấy chưa bị phá hủy.","chuHienThoi":"không rõ","congNang":["Liên quan Đoạn Không cấm trận có khả năng che thần thức dò xét @c1764"],"chuSoHuu":[{"ten":"Cấm Ma Tông","tuChuong":"@c1764","denChuong":"","cachCoDuoc":"vật của tông môn được nhắc qua điều tra sau kịch biến Đan Hải","trangThai":"thất lạc"}],"capNhatToi":"@c1764","tabs":{"tienTrinh":[{"chuong":"@c1764","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị nhắc trong truy xét Lưu Chi Nguyên","text":"Lão già họ Triệu nói la bàn Đoạn Không cấm biến mất trên đường sau kịch biến Đan Hải nhưng chưa bị hủy, khiến phe Lục Ma Châu nghi Vương Lâm có liên quan.","anchor":"Mà la bàn Đoạn Không cấm trên đường biến mất!"}]},"nguon":["@c1764"]},{"id":"mot-lan-tinh-toan-cua-thanh-nguu-lao-to","name":"Một lần tính toán của Thanh Ngưu lão tổ","cn":"","aliases":[],"category":"khac","categoryLabel":"Lời hứa trợ lực","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"còn hiệu lực","blurb":"Một trợ lực Thanh Ngưu chân nhân từng hứa dành cho Vương Lâm trong thời khắc mấu chốt.","detail":"Được Vương Lâm xem là một trong ba lễ vật nặng ân tình của Thanh Ngưu chân nhân, có thể giúp hắn một lần ở thời khắc then chốt và thậm chí đảo ngược cục diện.","congNang":["Trợ giúp Vương Lâm một lần trong thời khắc mấu chốt @c1765"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1765","denChuong":"","cachCoDuoc":"Thanh Ngưu chân nhân hứa trợ lực như một lễ vật","trangThai":"đang giữ quyền dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1765","loai":"nhắc tới","importance":"normal","giaiDoan":"Lễ vật của Thanh Ngưu chân nhân","text":"Vương Lâm nhớ lại một lần tính toán Thanh Ngưu chân nhân đã hứa, coi đây là lễ vật có thể trợ giúp ở thời khắc mấu chốt.","anchor":"trong thời khắc mấu chốt trợ giúp Vương Lâm một lần"}]},"nguon":["@c1765"]},{"id":"dan-duoc-viem-loan-de-lai","name":"Đan dược Viêm Loan để lại","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược trị thương","phamCap":"không rõ","soHuu":["Vương Lâm","Viêm Loan"],"trangThai":"đã giao cho Vương Lâm","blurb":"Viên đan dược trị thương Viêm Loan để lại cho Vương Lâm sau khi đề nghị hợp tác.","detail":"Viêm Loan đặt viên đan xuống đất trước khi rời động phủ. Vương Lâm thu vào tay, nhận ra hương thơm mát và công hiệu trị thương tốt.","congNang":["Trị thương, được Vương Lâm đánh giá có công hiệu tốt @c1765"],"chuSoHuu":[{"ten":"Viêm Loan","tuChuong":"@c1765","denChuong":"@c1765","cachCoDuoc":"Mang theo bên người trước khi tới động phủ","trangThai":"đã giao đi"},{"ten":"Vương Lâm","tuChuong":"@c1765","denChuong":"","cachCoDuoc":"Viêm Loan để lại trước khi rời động phủ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1765","loai":"đổi chủ","importance":"normal","giaiDoan":"Viêm Loan tặng đan","text":"Viêm Loan để lại một viên đan dược trị thương trước khi rời khỏi động phủ của Vương Lâm.","anchor":"hiển nhiên rất tốt để trị thương"}]},"nguon":["@c1765"]},{"id":"la-ban-hu-ao-cua-nu-tu-luc-ma-chau","name":"La bàn hư ảo của nữ tu Lục Ma Châu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật phẩm dò tìm","phamCap":"Không rõ","soHuu":["Nữ tu Không Kiếp sơ kỳ dùng la bàn hư ảo"],"trangThai":"đang sử dụng","blurb":"La bàn hư ảo do nữ tu Không Kiếp sơ kỳ của Lục Ma Châu sử dụng ở hậu phương. Nó hiển thị rõ vị trí Vương Lâm và hỗ trợ truyền tin cho các đội truy kích.","detail":"Trong đội hình mấy ngàn tu sĩ Lục Ma Châu, nữ tu Không Kiếp sơ kỳ khoanh chân trước la bàn hư ảo, nhờ đó theo dõi vị trí Vương Lâm và thông báo cho các nhóm truy đuổi ở xa.","phanLoaiPhu":"Dò tìm và liên lạc","hinhDang":"La bàn hư ảo lơ lửng","congNang":["Hiển thị vị trí Vương Lâm cho lực lượng Lục Ma Châu @c1767","Hỗ trợ truyền tin vị trí tới các đội truy đuổi @c1767"],"chuSoHuu":[{"ten":"Nữ tu Không Kiếp sơ kỳ dùng la bàn hư ảo","tuChuong":"@c1767","denChuong":"","cachCoDuoc":"Đang sử dụng trong hậu phương Lục Ma Châu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1767","loai":"dùng","importance":"normal","giaiDoan":"Theo dõi truy sát","text":"Nữ tu Không Kiếp sơ kỳ dùng la bàn hư ảo để hiển thị vị trí Vương Lâm và điều phối truy binh Lục Ma Châu.","anchor":"trước mặt lơ lửng một la bàn hư ảo, bên trong hiển thị rõ ràng vị trí"}]},"capNhatToi":"@c1767","nguon":["@c1767"]},{"id":"u-minh-thu","name":"U Minh Thú","cn":"","aliases":["Thiên Đạo của Vương Lâm"],"category":"khac","categoryLabel":"Thiên Đạo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang theo Vương Lâm","blurb":"U Minh Thú là Thiên Đạo của Vương Lâm, hiện ra từ viên đá màu đen trong trận đấu với Hứa Đức Tài. Nó nuốt Thiên Đạo kình ngư của Hứa Đức Tài, cho thấy năng lực cắn nuốt Thiên Đạo khác.","detail":"U Minh Thú là Thiên Đạo của Vương Lâm, ẩn trong viên đá màu đen mang theo bên người. Khi hư ảnh kình ngư Thiên Đạo của Hứa Đức Tài tiếp tục cắn nuốt, Vương Lâm phun ra viên đá màu đen và triệu gọi U Minh Thú. U Minh Thú hút nuốt kình ngư vào miệng, khiến Hứa Đức Tài thổ huyết và kêu mất Thiên Đạo. Năng lực cắn nuốt Thiên Đạo khác của nó được hé lộ thông qua Không Gian Thạch trong cơ thể @c1768.","dinhDanh":"goc","phanLoaiPhu":"Thiên Đạo","hinhDang":"U Minh Thú hiện ra từ viên đá màu đen","nguonGoc":"Thiên Đạo của Vương Lâm","uyLuc":"Có thể nuốt Thiên Đạo kình ngư của Hứa Đức Tài.","dacDiem":"Năng lực cắn nuốt Thiên Đạo khác được hé lộ thông qua Không Gian Thạch trong cơ thể nó.","chuHienThoi":"Vương Lâm","congNang":["Nuốt Thiên Đạo khác, cụ thể là hư ảnh kình ngư của Hứa Đức Tài @c1768"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1768","denChuong":"","cachCoDuoc":"Thiên Đạo của Vương Lâm hiện ra từ viên đá màu đen","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"khai phong","importance":"major","giaiDoan":"Nuốt Thiên Đạo kình ngư","text":"U Minh Thú hiện ra từ viên đá màu đen của Vương Lâm và nuốt Thiên Đạo kình ngư của Hứa Đức Tài.","anchor":"Vật này chính là Thiên Đạo của Vương Lâm, U Minh Thú"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"la-ban-hu-ao-truy-tung-vuong-lam","name":"La bàn hư ảo truy tung Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo truy tung","phamCap":"Không rõ","soHuu":["Nữ tu Không Kiếp bên cạnh Cực Thiên thảo nguyên"],"trangThai":"dang-co","blurb":"La bàn hư ảo trước mặt nữ tu Không Kiếp, dùng để hiển thị vị trí Vương Lâm và các nhóm điểm sáng xanh biếc trên Cực Thiên thảo nguyên.","detail":"Pháp bảo này giúp nữ tu Không Kiếp quan sát rõ vị trí Vương Lâm, nhận ra hắn liên tục biến mất rồi xuất hiện cạnh các nhóm tu sĩ Lục Ma Châu và điều phối việc báo động truy sát.","congNang":["Truy tung điểm sáng mục tiêu và các nhóm tu sĩ trên la bàn @c1769"],"chuSoHuu":[{"ten":"Nữ tu Không Kiếp bên cạnh Cực Thiên thảo nguyên","tuChuong":"@c1769","denChuong":"","cachCoDuoc":"Đang sử dụng khi truy tung Vương Lâm","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Truy tung điểm sáng","text":"La bàn hư ảo hiển thị rõ vị trí Vương Lâm để nữ tu Không Kiếp theo dõi biến hóa truy sát.","anchor":"La bàn hư ảo phía trước nàng giờ phút này hiển thị rõ ràng vị trí của Vương Lâm"}]},"nguon":["@c1769"]},{"id":"la-ban-cua-vuong-lam-doat-duoc","name":"La bàn của Vương Lâm đoạt được","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo truy tung","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"La bàn Vương Lâm đoạt được và dùng làm mồi nhử trong kế kim thiền thoát xác.","detail":"Vương Lâm đã hiểu rõ kết cấu và cấm chế bên trong la bàn, nhập thần trí vào nguyên thần bị xóa ý chí để điều khiển nó bay đi. Cuối chương, la bàn bị hai lão quái Không Kiếp trung kỳ đuổi kịp và phá hủy.","dacDiem":"Kết cấu và cấm chế bên trong đã bị Vương Lâm nhìn thấu.","congNang":["Làm mồi nhử kéo nhóm truy sát rời khỏi vị trí thật của Vương Lâm @c1769"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1769","denChuong":"@c1769","cachCoDuoc":"Đoạt được trước đó và dùng làm mồi nhử","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Mồi nhử bị phá","text":"Vương Lâm dùng la bàn làm mồi nhử truy sát, sau đó cảm nhận rõ nó tan nát khi bị hai lão quái đuổi kịp.","anchor":"Thật tiếc cái la bàn này chẳng qua kết cấu và cấm chế bên trong nó ta cũng đã hiểu rõ"}]},"nguon":["@c1769"]},{"id":"chiec-o-mau-lam","name":"Chiếc ô màu lam","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã tự bạo","blurb":"Chiếc ô màu lam là pháp bảo được Vương Lâm sử dụng bên trong Không Gian Thạch, dùng để dung hợp và thay thế bầu trời trong sát trận. Tính tới mốc mới nhất, chiếc ô đã tự bạo nhằm cản công kích và giúp chủ nhân đổi hướng thoát thân.","detail":"Khi dựng sát trận trong Không Gian Thạch, Vương Lâm huyễn hóa chiếc ô màu lam, cho nó bay lên cao và chậm rãi thay thế thiên không bên trong (@c1769). Về sau, trong lúc đối mặt với lục mang của Trương Đạo Tông, Vương Lâm cho chiếc ô tự bạo để cản công kích, đồng thời mượn lực trùng kích rơi xuống gần đại địa mà đổi hướng thoát thân (@c1774).","congNang":["Dung hợp và thay thế bầu trời trong không gian sát trận @c1769","Tự bạo để cản công kích và tạo lực trùng kích giúp chủ nhân đổi hướng thoát thân @c1774"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1769","denChuong":"@c1774","cachCoDuoc":"Đã có trong tay khi bị Trương Đạo Tông truy sát","trangThai":"đã tự bạo"}],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Hóa thành thiên không","text":"Chiếc ô màu lam bay lên bầu trời trong Không Gian Thạch và dung hợp vào thiên không của sát trận.","anchor":"Lập tức chiếc ô màu lam huyễn hóa ra, bay thẳng lên bầu trời"},{"chuong":"@c1774","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Tự bạo phá vây","text":"Vương Lâm cho chiếc ô màu lam tự bạo để cản lục mang của Trương Đạo Tông và mượn lực rơi xuống gần đại địa.","anchor":"trước người của hắn xuất hiện cái ô màu lam kia"}]},"nguon":["@c1769","@c1774"],"uyLuc":"Tự bạo đủ để cản lục mang của Trương Đạo Tông @c1774","dacDiem":"Có thể huyễn hóa bay lên cao và dung hợp vào thiên không của sát trận @c1769"},{"id":"kim-an-huyen-la-tang","name":"Kim ấn Huyền La tặng","cn":"","category":"phap-bao","categoryLabel":"Ấn pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Kim ấn do Huyền La tặng Vương Lâm, được đưa vào Không Gian Thạch và hóa thành mặt trời màu vàng trong sát trận.","detail":"Vương Lâm thổi nguyên thần khí vào kim ấn, khiến nó lan kim quang vạn trượng rồi bay lên bầu trời trong Không Gian Thạch, hình thành mặt trời vàng của không gian sát trận.","nguonGoc":"Huyền La tặng Vương Lâm.","congNang":["Hóa thành mặt trời màu vàng trong Không Gian Thạch @c1769"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1769","denChuong":"","cachCoDuoc":"Được Huyền La tặng và đang sở hữu","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Mặt trời vàng","text":"Kim ấn Huyền La tặng phát kim quang vạn trượng và hóa thành mặt trời vàng trong sát trận.","anchor":"kim ấn lan ra kim quang vạn trượng, được Vương Lâm tung lên"}]},"nguon":["@c1769"]},{"id":"van-vuong","name":"Văn Vương","aliases":["Văn Thú"],"category":"khac","categoryLabel":"Linh vật pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Văn Vương được Vương Lâm lấy ra trong quá trình dựng sát trận, biến hóa thân hình rồi ẩn vào mây trắng.","detail":"Trong Không Gian Thạch, Văn Vương nhoáng lên, thân hình biến hóa và ẩn vào tầng mây trắng trên bầu trời của sát trận.","congNang":["Ẩn vào tầng mây của sát trận @c1769"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1769","denChuong":"","cachCoDuoc":"Đang được Vương Lâm sử dụng trong sát trận","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"dùng","importance":"normal","giaiDoan":"Ẩn vào mây","text":"Văn Vương biến hóa thân hình rồi ẩn vào mây trắng trong Không Gian Thạch.","anchor":"Cuối cùng hắn lấy ra Văn Vương. Văn Vương nhoáng một cái"}]},"nguon":["@c1769"]},{"id":"thien-dao-cua-hua-duc-tai","name":"Thiên Đạo của Hứa Đức Tài","cn":"","aliases":["Thiên Đạo kình ngư","Thiên Đạo của Hứa Đức Tài"],"category":"khac","categoryLabel":"Linh thể liên hệ tâm thần","phamCap":"Không rõ","soHuu":["Hứa Đức Tài"],"trangThai":"bị Vương Lâm nuốt","blurb":"Linh thể tâm thần tương liên với Hứa Đức Tài. Việc nó bị Vương Lâm nuốt khiến Hứa Đức Tài bị thương, nguyên thần uể oải và sinh hận sâu.","detail":"Thiên Đạo này có liên hệ tâm thần với Hứa Đức Tài. Sau khi bị Vương Lâm nuốt, Hứa Đức Tài bị thương trong người và rời khỏi chiến trường với nguyên thần uể oải.","phanLoaiPhu":"linh thể liên hệ tâm thần","dacDiem":"Tâm thần tương liên với Hứa Đức Tài.","chuHienThoi":"Hứa Đức Tài","congNang":["Liên hệ tâm thần với Hứa Đức Tài, khi bị nuốt khiến hắn chịu thương thế @c1770"],"chuSoHuu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1770","denChuong":"","cachCoDuoc":"Tâm thần tương liên từ trước khi chương diễn ra","trangThai":"đã mất"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"nhắc tới","importance":"normal","giaiDoan":"Hậu quả bị nuốt","text":"Thiên Đạo của Hứa Đức Tài đã bị Vương Lâm nuốt, khiến Hứa Đức Tài thương thế trong người và nguyên thần uể oải.","anchor":"Thiên Đạo đó tâm thần tương liên với hắn"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"la-ban-theo-doi-cua-luc-ma-chau","name":"La bàn theo dõi của Lục Ma Châu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo theo dõi","phamCap":"Không rõ","soHuu":["Nữ tử tu sĩ Không Kiếp sơ kỳ của Lục Ma Châu"],"trangThai":"đang dùng","blurb":"La bàn được nữ tử Không Kiếp sơ kỳ Lục Ma Châu dùng để theo dõi điểm sáng đại biểu Hứa Đức Tài. Khi điểm sáng biến mất, phe Lục Ma Châu lập tức biết hắn mất tích.","detail":"La bàn đặt trước mặt nữ tử Không Kiếp sơ kỳ, hiển thị điểm sáng đại biểu cho Hứa Đức Tài. Biến cố điểm sáng biến mất khiến nàng kinh hãi và truyền tin cho ba tu sĩ Không Kiếp trên Cực Thiên thảo nguyên.","phanLoaiPhu":"pháp bảo theo dõi","congNang":["Theo dõi điểm sáng đại biểu cho Hứa Đức Tài trong chiến trường @c1770"],"chuSoHuu":[{"ten":"Nữ tử tu sĩ Không Kiếp sơ kỳ của Lục Ma Châu","tuChuong":"@c1770","denChuong":"","cachCoDuoc":"Đang điều khiển trong đội hình Lục Ma Châu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"dùng","importance":"normal","giaiDoan":"Phát hiện Hứa Đức Tài mất tích","text":"Nữ tử Không Kiếp sơ kỳ nhìn la bàn và phát hiện điểm sáng đại biểu Hứa Đức Tài biến mất.","anchor":"Nàng nhìn la bàn trước mặt, cảm giác dựng tóc gáy"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"den-long-cua-hua-duc-tai","name":"Đèn lồng của Hứa Đức Tài","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hộ thân","phamCap":"Không rõ","soHuu":["Hứa Đức Tài"],"trangThai":"đang dùng","blurb":"Đèn lồng của Hứa Đức Tài là pháp bảo hộ thân lơ lửng trên đỉnh đầu hắn, nhiều lần tỏa sáng bảo vệ cả thân thể lẫn nguyên thần. Nhờ nó, Hứa Đức Tài sống sót qua nhiều đợt vây sát và chưa bị Vương Lâm giết chết.","detail":"Đèn lồng xuất hiện trên đỉnh đầu Hứa Đức Tài trong sát trận, bảo hộ hắn sau đợt chém giết của sáu đạo bổn nguyên và nhiều lần chống đỡ các đợt công kích tiếp theo @c1771. Đèn có liên hệ mật thiết với Hứa Đức Tài, đến mức khi thân thể bị đánh nát nó vẫn giữ được nguyên thần cho hắn. Chính vì mối liên hệ này mà Vương Lâm nhận ra muốn giết đối phương thì phải chặt đứt sợi dây gắn kết giữa người và đèn.","hinhDang":"Một cái đèn lồng lơ lửng trên đỉnh đầu Hứa Đức Tài.","chuHienThoi":"Hứa Đức Tài","congNang":["Tỏa ánh sáng bảo vệ thân thể Hứa Đức Tài trước các đợt vây sát @c1771","Bảo vệ nguyên thần Hứa Đức Tài khi thân thể bị đánh nát @c1771"],"chuSoHuu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1771","denChuong":"","cachCoDuoc":"Đã mang theo khi giao chiến với Vương Lâm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1771","loai":"xuất hiện","importance":"major","giaiDoan":"Hộ thân trong sát trận","text":"Đèn lồng lơ lửng trên đỉnh đầu Hứa Đức Tài, tỏa sáng bảo vệ khiến hắn sống sót qua nhiều đợt vây sát của Vương Lâm.","anchor":"Trên đỉnh đầu hắn lơ lửng một cái đèn lồng"}]},"capNhatToi":"@c1771","nguon":["@c1771"],"uyLuc":"Giữ cho Hứa Đức Tài sống sót qua nhiều đợt vây sát của Vương Lâm, bảo toàn nguyên thần ngay cả khi thân thể bị đánh nát @c1771.","dacDiem":"Lơ lửng trên đỉnh đầu Hứa Đức Tài và có liên hệ mật thiết với hắn, phải chặt đứt liên hệ này mới có thể giết được người @c1771."},{"id":"quy-hon-hua-duc-tai","name":"Quỷ hồn Hứa Đức Tài","cn":"","category":"khac","categoryLabel":"Quỷ hồn/vật thu giữ","phamCap":"hiếm gặp","soHuu":["Vương Lâm"],"trangThai":"bị Vương Lâm thu giữ","blurb":"Quỷ hồn Hứa Đức Tài là quỷ hồn tự sinh từ oán khí không cam lòng của Hứa Đức Tài sau khi chết. Sau khi nguyên thần tan rã, oán khí ngưng tụ khiến hắn hóa thành quỷ hồn tự nhiên cực hiếm, từng khiến Vương Lâm mê man thoáng chốc rồi bỏ chạy nhưng lập tức bị bắt và thu vào Không Gian trữ vật.","detail":"Quỷ hồn này sinh ra từ oán khí không cam lòng của Hứa Đức Tài sau khi chết. Khi nguyên thần Hứa Đức Tài tan rã, oán khí ngưng tụiến hắn hình thành quỷ hồn tự nhiên thuộc loại cực hiếm. Quỷ hồn từng khiến Vương Lâm mê man trong thoáng chốc rồi bỏ chạy, nhưng ngay sau đó bị Vương Lâm bắt lại và thu vào Không Gian trữ vật, do có tác dụng lớn đối với người tu Đa Trọng Huyễn Thuật.","phanLoaiPhu":"quỷ hồn tự sinh","nguonGoc":"Sinh ra từ oán khí không cam lòng của Hứa Đức Tài sau khi chết","congNang":["Có tác dụng lớn với người tu Đa Trọng Huyễn Thuật @c1772","Từng khiến Vương Lâm mê man trong thoáng chốc @c1772"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1772","denChuong":"","cachCoDuoc":"truy bắt sau khi Hứa Đức Tài chết hóa quỷ hồn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1772","loai":"xuất hiện","importance":"major","giaiDoan":"Tự sinh rồi bị bắt","text":"Quỷ hồn Hứa Đức Tài tự sinh từ oán khí sau khi chết, bỏ chạy nhưng bị Vương Lâm bắt và thu vào Không Gian trữ vật.","anchor":"Hắn hiểu rõ một người hoặc mãnh thú tử vong nếu có thể tự mình sinh ra quỷ hồn"}]},"capNhatToi":"@c1772","nguon":["@c1772"],"dacDiem":"Quỷ hồn tự sinh từ oán khí, thuộc loại tự nhiên cực hiếm @c1772"},{"id":"thien-nguu-hon-khai","name":"Thiên Ngưu Hồn Khải","aliases":["Hồn Khải"],"cn":"","category":"phap-bao","categoryLabel":"Hồn khải","phamCap":"Không rõ","soHuu":["Thiên Ngưu","Vương Lâm","Thiên Ngưu Châu"],"trangThai":"Đang được Vương Lâm sử dụng","blurb":"Thiên Ngưu Hồn Khải là bộ áo giáp linh hồn hóa từ hư ảnh Thiên Ngưu bị kéo ra khỏi không gian phong ấn, mang khí tức linh hồn cường đại. Nó giúp Vương Lâm tạm thời bộc phát lực lượng đỉnh phong, đạt chiến lực gần Không Kiếp hậu kỳ, song trạng thái này bị phe Lục Ma Châu nhận ra.","detail":"Thiên Ngưu Hồn Khải hình thành trong nghi thức tại Địa Cung, khi hư ảnh Thiên Ngưu bị kéo ra khỏi dòng xoáy và co rút thành một bộ áo giáp lơ lửng phía trên dòng xoáy, tỏa ra khí tức linh hồn cường đại @c1776. Sự xuất hiện của nó khiến Lữ Văn Nhiễm muốn chiếm lấy, buộc Vương Lâm lập tức ra tay ngăn cản. Cơ duyên này không chỉ tạm thời tăng tu vi cho người nhận mà còn hỗ trợ con đường đạt cảnh giới cao hơn về sau @c1776. Về sau, Vương Lâm sử dụng Thiên Ngưu Hồn Khải để tạm thời bộc phát lực lượng đỉnh phong, đạt chiến lực gần Không Kiếp hậu kỳ, nhưng trạng thái này bị phe Lục Ma Châu nhận ra @c1782.","phanLoaiPhu":"áo giáp linh hồn","hinhDang":"bộ áo giáp","nguonGoc":"Hóa từ hư ảnh Thiên Ngưu bị kéo ra khỏi không gian phong ấn","uyLuc":"Giúp Vương Lâm tạm thời bộc phát lực lượng đỉnh phong, đạt chiến lực gần Không Kiếp hậu kỳ @c1782","dacDiem":"Mang khí tức linh hồn cường đại, hình thành từ hư ảnh Thiên Ngưu co rút thành bộ áo giáp lơ lửng phía trên dòng xoáy trong đại trận tại Địa Cung.","chuHienThoi":"chưa định chủ","congNang":["Tạm thời tăng tu vi cho người nhận @c1776","Hỗ trợ người nhận ngày sau dễ đạt cảnh giới cao hơn @c1776","Tạm đổi lấy lực lượng đỉnh phong, khiến Vương Lâm đạt chiến lực gần Không Kiếp hậu kỳ @c1782"],"chuSoHuu":[{"ten":"Thiên Ngưu","tuChuong":"@c1776","denChuong":"","cachCoDuoc":"Hồn phách bị kéo ra và hóa thành áo giáp","trangThai":"nguồn gốc của Hồn Khải"},{"ten":"Lữ Văn Nhiễm","tuChuong":"@c1776","denChuong":"","cachCoDuoc":"Định lao tới chiếm lấy sau nghi thức","trangThai":"đang tranh đoạt"},{"ten":"Vương Lâm","tuChuong":"@c1776","denChuong":"","cachCoDuoc":"Được Thiên Ngưu tán thành và khoác lực lượng Hồn Khải","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1776","loai":"xuất hiện","importance":"major","giaiDoan":"Hóa thành áo giáp","text":"Hư ảnh Thiên Ngưu bị kéo ra khỏi dòng xoáy, co rút thành một bộ áo giáp lơ lửng phía trên dòng xoáy và lập tức trở thành mục tiêu tranh đoạt.","anchor":"hư ảnh Thiên Ngưu nhanh chóng co rút lại, cuối cùng bất ngờ hóa thành một bộ áo giáp","phamCap":"Không rõ"},{"chuong":"@c1782","loai":"dùng","importance":"major","giaiDoan":"Tăng phúc chiến lực","text":"Thiên Ngưu Hồn Khải giúp Vương Lâm tạm thời bộc phát lực lượng đỉnh phong, nhưng phe Lục Ma Châu nhận ra trạng thái này có thời hạn.","anchor":"Bọn họ có thể đổi lấy lực lượng đỉnh phong nhưng chỉ là tạm thời","phamCap":"Không rõ"}]},"capNhatToi":"@c1776","nguon":["@c1776","@c1782"]},{"id":"day-chuyen-huyet-sac","name":"Dây chuyền huyết sắc","cn":"","category":"khac","categoryLabel":"Vật do máu hiến tế ngưng tụ","phamCap":"Không rõ","soHuu":["Lão già họ Chu"],"trangThai":"đã dùng trong nghi thức","blurb":"Dây chuyền huyết sắc do chín tia máu của hơn ngàn tu sĩ ngưng tụ thành trong nghi thức gọi Thiên Ngưu Hồn. Nó chui vào dòng xoáy, khóa kéo hồn phách Thiên Ngưu và cần Nguyên Thần các tu sĩ Không Kiếp hợp lực mới kéo tiếp được.","detail":"Trong nghi thức Hồn Khải, hơn ngàn tu sĩ hiến máu theo lệnh lão già họ Chu. Máu hợp thành dây chuyền huyết sắc, chui vào dòng xoáy và khóa lấy Thiên Ngưu Hồn để kéo hư ảnh khổng lồ ra ngoài.","phanLoaiPhu":"dây chuyền huyết sắc do máu ngưng tụ","vatLieu":"máu tươi của hơn ngàn tu sĩ","nguonGoc":"Sinh ra trong nghi thức gọi Thiên Ngưu Hồn","congNang":["Khóa kéo hồn phách Thiên Ngưu trong dòng xoáy @c1776"],"chuSoHuu":[{"ten":"Lão già họ Chu","tuChuong":"@c1776","denChuong":"","cachCoDuoc":"Dẫn nghi thức khiến máu hơn ngàn tu sĩ ngưng thành dây chuyền","trangThai":"điều khiển trong nghi thức"}],"tabs":{"tienTrinh":[{"chuong":"@c1776","loai":"xuất hiện","importance":"normal","giaiDoan":"Khóa Thiên Ngưu Hồn","text":"Máu của hơn ngàn tu sĩ ngưng thành dây chuyền huyết sắc, chui vào dòng xoáy và khóa kéo hồn phách Thiên Ngưu.","anchor":"Một lượng lớn máu tươi trong nháy mắt ngưng tụ lại một chỗ, bất ngờ hóa thành một cái dây chuyền huyết sắc","phamCap":"Không rõ"}]},"capNhatToi":"@c1776","nguon":["@c1776"]},{"id":"dau-lau-luu-chi-nguyen","name":"Đầu lâu Lưu Chi Nguyên","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật chứng","phamCap":"Đầu lâu tu sĩ Không Kiếp","soHuu":["Vương Lâm"],"trangThai":"được Vương Lâm dùng làm vật chứng","blurb":"Đầu lâu của Lưu Chi Nguyên được Vương Lâm lấy ra trong Địa Cung để chứng minh hắn đã giết một tu sĩ Không Kiếp của Lục Ma Châu.","detail":"Vương Lâm biến ra đầu lâu Lưu Chi Nguyên trên lòng bàn tay giữa cuộc tranh luận về tư cách nhận Hồn Khải. Vật chứng này khiến hơn một ngàn tu sĩ trong Địa Cung chấn động, đồng thời buộc Lữ Văn Nhiễm phải chuyển sang cáo buộc Vương Lâm giả mạo công lao.","congNang":["Làm vật chứng cho công lao Vương Lâm giết Lưu Chi Nguyên trong cuộc tranh tư cách nhận Hồn Khải @c1777"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1777","denChuong":"","cachCoDuoc":"lấy ra từ tay áo và biến hiện trên lòng bàn tay để chứng minh chiến công","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1777","loai":"xuất hiện","importance":"normal","giaiDoan":"Vật chứng công lao","text":"Đầu lâu Lưu Chi Nguyên xuất hiện trên lòng bàn tay Vương Lâm, trở thành bằng chứng khiến Địa Cung chấn động về chiến công giết tu sĩ Không Kiếp Lục Ma Châu.","anchor":"Lập tức đầu lâu của Lưu Chi Nguyên biến ảo ra, xuất hiện trên lòng bàn tay hắn"}]},"nguon":["@c1777"]},{"id":"dau-lau-hua-duc-tai","name":"Đầu lâu Hứa Đức Tài","cn":"","aliases":[],"category":"khac","categoryLabel":"Chiến lợi phẩm","phamCap":"Đầu lâu tu sĩ Không Kiếp sơ kỳ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm giữ","blurb":"Đầu lâu của Hứa Đức Tài, Đại Tôn Không Kiếp sơ kỳ Lục Ma Châu. Vương Lâm lấy nó ra tại Địa Cung để chứng minh chiến công trước lời vu cáo của Lữ Văn Nhiễm.","detail":"Đầu lâu được đặt cạnh đầu lâu Lưu Chi Nguyên, trở thành chứng cứ thứ hai cho việc Vương Lâm giết tu sĩ Không Kiếp phe Lục Ma Châu. Sự xuất hiện của nó khiến tu sĩ Địa Cung chấn động và làm Lữ Văn Nhiễm khó tiếp tục phủ nhận công lao của Vương Lâm.","congNang":["Làm bằng chứng trực tiếp cho chiến công giết Hứa Đức Tài của Vương Lâm @c1778"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1778","denChuong":"","cachCoDuoc":"Lấy ra trước đám tu sĩ Địa Cung như chiến lợi phẩm đã có trong tay.","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1778","loai":"xuất hiện","importance":"normal","giaiDoan":"Bằng chứng chiến công","text":"Vương Lâm lấy đầu lâu Hứa Đức Tài ra, khiến địa cung chấn động vì đây là Đại Tôn Không Kiếp sơ kỳ của Lục Ma Châu.","anchor":"Cái đầu lâu này chính là của Hứa Đức Tài"}]},"capNhatToi":"@c1778","nguon":["@c1778"]},{"id":"banh-xe-chin-rang-cua-cua-lu-van-nhiem","name":"Bánh xe chín răng cưa của Lữ Văn Nhiễm","cn":"","aliases":["Bánh xe răng cưa"],"category":"phap-bao","categoryLabel":"Pháp bảo công kích","phamCap":"không rõ","soHuu":["Lữ Văn Nhiễm"],"trangThai":"hư tổn","blurb":"Pháp bảo công kích hình bánh xe chín răng cưa được Lữ Văn Nhiễm dùng để đánh Vương Lâm trong Địa Cung.","detail":"Lữ Văn Nhiễm triệu ra bánh xe chín răng cưa và đập xuống Vương Lâm. Khi va chạm với Tê Thiên, bánh xe bị bẻ gãy bốn răng, nhưng năm răng còn lại vẫn đánh trúng khiến Vương Lâm phun sương máu.","phanLoaiPhu":"pháp bảo công kích","hinhDang":"bánh xe với chín răng cưa","uyLuc":"Có thể tiếp tục gây trọng thương dù đã bị Tê Thiên bẻ gãy bốn răng.","dacDiem":"Chín răng cưa, sau va chạm còn năm răng đánh trúng mục tiêu.","chuHienThoi":"Lữ Văn Nhiễm","capNhatToi":"@c1779","congNang":["Cắt chém và đánh thẳng vào thân thể mục tiêu @c1779"],"chuSoHuu":[{"ten":"Lữ Văn Nhiễm","tuChuong":"@c1779","denChuong":"","cachCoDuoc":"đã sở hữu khi giao chiến trong Địa Cung","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1779","loai":"dùng","importance":"normal","giaiDoan":"Đánh Vương Lâm","text":"Lữ Văn Nhiễm triệu bánh xe chín răng cưa đánh Vương Lâm; pháp bảo bị Tê Thiên bẻ gãy bốn răng nhưng vẫn khiến Vương Lâm phun sương máu.","anchor":"một bánh xe với chín răng cưa xuất hiện, bị hắn nắm trong tay","phamCap":"không rõ"}]},"nguon":["@c1779"]},{"id":"den-long-ho-than-cua-vuong-lam","name":"Đèn lồng hộ thân của Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hộ thân","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Pháp bảo hộ thân xuất hiện trên đỉnh đầu Vương Lâm khi hắn bị bánh xe chín răng cưa đánh trúng.","detail":"Sau khi Vương Lâm không bị bánh xe cắt đôi, một chiếc đèn lồng tỏa ánh sáng nhu hòa xuất hiện trên đỉnh đầu hắn. Ánh sáng bao phủ thân thể, giúp hắn chống đỡ thương thế và nhanh chóng khôi phục đau đớn sau đòn nặng.","phanLoaiPhu":"pháp bảo hộ thân","hinhDang":"đèn lồng tỏa ánh sáng nhu hòa","uyLuc":"Có thể bao phủ thân thể Vương Lâm và hỗ trợ khôi phục sau khi bị pháp bảo mạnh đánh trúng.","dacDiem":"Ánh sáng nhu hòa bao quanh toàn thân.","chuHienThoi":"Vương Lâm","capNhatToi":"@c1779","congNang":["Hộ thân và hỗ trợ khôi phục thương thế sau khi bị công kích @c1779"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1779","denChuong":"","cachCoDuoc":"xuất hiện hộ thân khi Vương Lâm bị bánh xe đánh trúng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1779","loai":"dùng","importance":"normal","giaiDoan":"Hộ thân sau trọng kích","text":"Đèn lồng xuất hiện trên đỉnh đầu Vương Lâm, tỏa ánh sáng nhu hòa bao phủ thân thể và giúp hắn khôi phục.","anchor":"xuất hiện một cái đèn lồng tỏa ánh sáng nhu hòa","phamCap":"không rõ"}]},"nguon":["@c1779"]},{"id":"luc-ma-kinh","name":"Lục Ma kính","cn":"","aliases":["Mặt gương màu lục","Mặt gương màu lục của Lục Ma sứ giả","Tấm gương màu lục"],"category":"phap-bao","categoryLabel":"Pháp bảo/trận tượng lục khí","phamCap":"không rõ","soHuu":["Lục Ma sứ giả","Bốn Lục Ma sứ giả"],"trangThai":"hong","blurb":"Lục Ma kính là mặt gương màu lục do bốn Lục Ma sứ giả ngưng tụ từ lục khí phóng ra từ thiên linh, trong gương hiện ra Lục Ma Châu. Nó phối hợp cùng bốn sứ giả để hình thành thế trấn áp trên Cực Thiên thảo nguyên, song khi bốn sứ giả gặp biến, mặt gương tan nát kéo theo hình chiếu Lục Ma Châu sụp đổ.","detail":"Bốn Lục Ma sứ giả phóng lục khí từ thiên linh, lục khí ngưng trên bầu trời thành mặt gương màu lục hiện cảnh Lục Ma Châu @c1781. Mặt gương hạ xuống bao phủ Cực Thiên thảo nguyên để hỗ trợ trấn áp khí tức bên dưới, rồi được bốn sứ giả kích hoạt, chìm vào lòng đất và lan rộng bao phủ toàn khu vực @c1782. Trong quá trình trấn áp, nó tạo và duy trì hình chiếu Lục Ma Châu bao trùm mục tiêu, đồng thời che chở bốn sứ giả trước chấn động từ Dịch Linh Ấn @c1782. Về sau, Lục Ma kính quanh bốn sứ giả tan nát, khiến hình chiếu Lục Ma Châu lập tức sụp đổ @c1783.","dinhDanh":"goc","hinhDang":"mặt gương màu lục","chuHienThoi":"Lục Ma sứ giả","congNang":["Hiện cảnh Lục Ma Châu trong gương @c1781","Hạ xuống bao phủ khu vực, phối hợp hình thành thế trấn áp @c1781","Che chở bốn Lục Ma sứ giả trước chấn động từ Dịch Linh Ấn @c1782","Tạo hình chiếu Lục Ma Châu bao phủ Cực Thiên thảo nguyên để trấn áp mục tiêu @c1782","Biến ảo và duy trì hình chiếu Lục Ma Châu @c1783"],"chuSoHuu":[{"ten":"Lục Ma sứ giả","tuChuong":"@c1781","denChuong":"","cachCoDuoc":"ngưng tụ bằng lục khí từ thiên linh khi lập thế trấn áp","trangThai":"đang dùng"},{"ten":"Bốn Lục Ma sứ giả","tuChuong":"@c1782","denChuong":"@c1783","cachCoDuoc":"Được triển khai bên ngoài thân thể bốn sứ giả","trangThai":"bị Tàn Dạ làm tan nát"}],"tabs":{"tienTrinh":[{"chuong":"@c1781","loai":"xuất hiện","importance":"normal","giaiDoan":"Trấn áp Cực Thiên","text":"Bốn Lục Ma sứ giả ngưng lục khí thành Lục Ma kính, hiện Lục Ma Châu và hạ xuống bao phủ Cực Thiên thảo nguyên.","anchor":"Lục khí này ngưng tụ trên bầu trời, hóa thành một mặt gương màu lục!"},{"chuong":"@c1782","loai":"khai phong","importance":"major","giaiDoan":"Tạo hình chiếu Lục Ma Châu","text":"Lục Ma kính được bốn Lục Ma sứ giả kích hoạt, chìm vào lòng đất và lan rộng bao phủ Cực Thiên thảo nguyên thành hình chiếu đại lục.","anchor":"cái gương này lan ra vô hạn, bao phủ cả Cực Thiên thảo nguyên","phamCap":"Không rõ"},{"chuong":"@c1783","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị Tàn Dạ phá","text":"Lục Ma kính quanh bốn Lục Ma sứ giả tan nát, kéo theo hình chiếu Lục Ma Châu lập tức sụp đổ.","anchor":"Lục Ma kính biến ảo ra bên ngoài thân thể bốn Lục Ma sứ giả bỗng nhiên tan nát"}]},"capNhatToi":"@c1781","nguon":["@c1781","@c1782","@c1783"],"uyLuc":"Bao phủ toàn bộ Cực Thiên thảo nguyên, hình thành thế trấn áp khí tức bên dưới và chống đỡ chấn động từ Dịch Linh Ấn @c1782","dacDiem":"Mặt gương màu lục do bốn Lục Ma sứ giả ngưng tụ từ lục khí phóng ra từ thiên linh, trong gương hiện Lục Ma Châu; sự tồn tại của nó gắn liền với bốn sứ giả, khi họ gặp biến thì gương tan nát và hình chiếu sụp đổ @c1783"},{"id":"phap-bao-phong-ho-cua-hai-nu-tu-khong-kiep-so-ky","name":"Pháp Bảo phòng hộ của hai nữ tu Không Kiếp sơ kỳ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"Không rõ","soHuu":["Hai nữ tu Không Kiếp sơ kỳ của Lục Ma Châu"],"trangThai":"Không rõ","blurb":"Pháp bảo phòng hộ mạnh nhất của hai nữ tu Không Kiếp sơ kỳ. Nó được dùng để chống Dịch Linh Ấn nhưng không ngăn được việc hai người mất thân thể.","detail":"Trước chưởng ấn kinh khủng của Vương Lâm, hai nữ tu Không Kiếp sơ kỳ thi triển phòng ngự và xuất ra Pháp Bảo phòng hộ mạnh nhất. Dù vậy, họ vẫn bị trọng thương tới mức thân thể nổ tung, chỉ còn Nguyên Thần.","phanLoaiPhu":"Pháp bảo phòng ngự","chuHienThoi":"Hai nữ tu Không Kiếp sơ kỳ của Lục Ma Châu","congNang":["Dùng để phòng hộ trước Dịch Linh Ấn của Vương Lâm @c1782"],"uyLuc":"Không chống nổi Dịch Linh Ấn trong trận này.","chuSoHuu":[{"ten":"Hai nữ tu Không Kiếp sơ kỳ của Lục Ma Châu","tuChuong":"@c1782","denChuong":"","cachCoDuoc":"Pháp bảo phòng hộ của chính họ","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1782","loai":"dùng","importance":"normal","giaiDoan":"Chống Dịch Linh Ấn","text":"Hai nữ tu dùng pháp bảo phòng hộ mạnh nhất để chống chưởng ấn của Vương Lâm nhưng vẫn bị đánh đến mất thân thể.","anchor":"thi triển ra thần thông phòng ngự cực mạnh của mình, xuất ra Pháp Bảo phòng hộ mạnh nhất","phamCap":"Không rõ"}]},"capNhatToi":"@c1782","nguon":["@c1782"]},{"id":"phap-bao-bon-mang-cua-hai-nu-tu-khong-kiep-so-ky","name":"Pháp Bảo bổn mạng của hai nữ tu Không Kiếp sơ kỳ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo bổn mạng","phamCap":"Không rõ","soHuu":["Hai nữ tu Không Kiếp sơ kỳ của Lục Ma Châu"],"trangThai":"Đang dùng","blurb":"Pháp bảo bổn mạng được hai nữ tu Không Kiếp sơ kỳ tế xuất khi chỉ còn Nguyên Thần. Nó được dùng để chống biển lửa Phần Giới Cổ Tán.","detail":"Sau khi thân thể nổ tung, hai nữ tu chỉ còn Nguyên Thần và bị biển lửa do Phần Giới Cổ Tán tạo ra bao phủ trong hình chiếu Lục Ma Châu. Hai người đồng loạt tế xuất Pháp Bảo bổn mạng, liên thủ gắng gượng chống cự.","phanLoaiPhu":"Pháp bảo bổn mạng","chuHienThoi":"Hai nữ tu Không Kiếp sơ kỳ của Lục Ma Châu","congNang":["Dùng để chống biển lửa Phần Giới Cổ Tán khi chủ nhân chỉ còn Nguyên Thần @c1782"],"chuSoHuu":[{"ten":"Hai nữ tu Không Kiếp sơ kỳ của Lục Ma Châu","tuChuong":"@c1782","denChuong":"","cachCoDuoc":"Pháp bảo bổn mạng của chính họ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1782","loai":"dùng","importance":"normal","giaiDoan":"Chống biển lửa","text":"Hai nữ tu tế xuất Pháp Bảo bổn mạng và liên thủ chống cự biển lửa Phần Giới Cổ Tán.","anchor":"đồng loạt tế xuất ra Pháp Bảo bổn mạng, liên thủ gắng gượng chống cự","phamCap":"Không rõ"}]},"capNhatToi":"@c1782","nguon":["@c1782"]},{"id":"ngoc-boi-an-trong-nguyen-than-cua-truong-dao-tong","name":"Ngọc bội ẩn trong Nguyên Thần của Trương Đạo Tông","cn":"","category":"phap-bao","categoryLabel":"Hộ thân vật","phamCap":"Không rõ","soHuu":["Trương Đạo Tông"],"trangThai":"hong","blurb":"Ngọc bội hộ thân được Trương Đạo Tông giấu trong Nguyên Thần. Khi chống Tàn Dạ, nó tỏa ánh sáng nhu hòa một lúc rồi vỡ tung.","detail":"Trương Đạo Tông phun ngọc bội từ trong Nguyên Thần ra để chắn trước người khi bị tín thuật Tàn Dạ công phá. Pháp bảo này phát ra ánh sáng nhu hòa nhưng không chịu nổi uy lực tín thuật, cuối cùng vỡ tung và không cứu được hắn khỏi cảnh Nguyên Thần tiêu tán dần.","phanLoaiPhu":"Hộ thân Nguyên Thần","hinhDang":"Ngọc bội","uyLuc":"Có thể tạm thời phát ánh sáng hộ thân trước tín thuật nhưng nhanh chóng bị phá.","dacDiem":"Ẩn trong Nguyên Thần của Trương Đạo Tông.","chuHienThoi":"Trương Đạo Tông","capNhatToi":"@c1783","congNang":["Hộ thân Nguyên Thần trước công kích của Tàn Dạ trong thời gian ngắn @c1783"],"chuSoHuu":[{"ten":"Trương Đạo Tông","tuChuong":"@c1783","denChuong":"@c1783","cachCoDuoc":"Đã ẩn trong Nguyên Thần trước khi thi triển hộ thân","trangThai":"bị vỡ"}],"tabs":{"tienTrinh":[{"chuong":"@c1783","loai":"dùng","importance":"normal","giaiDoan":"Chống Tàn Dạ","text":"Trương Đạo Tông phun ngọc bội từ Nguyên Thần để hộ thân trước tín thuật Tàn Dạ nhưng ngọc bội bị phá vỡ.","anchor":"Phun ra một ngọc bội ẩn trong Nguyên Thần, cầm giơ lên trước người."}]},"nguon":["@c1783"]},{"id":"hac-giay-mau-luc","name":"Hạc giấy màu lục","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"không rõ","soHuu":["Lục Ma sứ giả cưỡi hạc giấy màu lục"],"trangThai":"không rõ","blurb":"Pháp bảo phi hành của Lục Ma sứ giả cưỡi hạc giấy màu lục. Nó được dùng để tăng tốc chạy về hướng tây sau khi bốn Lục Ma sứ giả tản ra.","detail":"Lục Ma sứ giả ngồi trên hạc giấy màu lục và triển khai tốc độ cao nhất để trốn khỏi Vương Lâm. Dù vậy, Vương Lâm vẫn xuất hiện chặn trước mặt hắn.","phanLoaiPhu":"pháp bảo phi hành","hinhDang":"hạc giấy màu lục","congNang":["Giúp chủ nhân phi hành đào tẩu với tốc độ cao @c1784"],"chuSoHuu":[{"ten":"Lục Ma sứ giả cưỡi hạc giấy màu lục","tuChuong":"@c1784","denChuong":"","cachCoDuoc":"đã sở hữu khi xuất hiện","trangThai":"đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c1784","loai":"dùng","importance":"normal","giaiDoan":"Đào tẩu hướng tây","text":"Lục Ma sứ giả dùng hạc giấy màu lục để chạy về hướng tây nhưng bị Vương Lâm chặn lại.","anchor":"Lục Ma sứ giả đang ngồi trên con hạc giấy"}]},"nguon":["@c1784"]},{"id":"hon-khai","name":"Hồn Khải","category":"phap-bao","categoryLabel":"Khải giáp","phamCap":"Không rõ","soHuu":["Vương Lâm","Người mặc Hồn Khải ở một huyệt khác"],"trangThai":"Đang tồn tại, nhưng bộ khải trên người trấn thủ huyệt khác đã bị đánh tan","blurb":"Khải giáp gắn với Thiên Ngưu Hồn và chỉ xuất hiện trên người được Thiên Ngưu tán thành. Chương này xác nhận những người mặc Hồn Khải chính là các nhân vật trấn thủ trong hệ thống Thiên Ngưu thất huyệt. (+) Giáp hoặc dấu hiệu gắn với Hồn khải sứ giả. Vương Lâm dựa vào đồ phổ từng xem để nhận ra hai áo đen không thuộc bốn mươi tám Dược Thiên Tôn có hồn khải mà hắn biết. [CAN-SOAT-GOP]","detail":"Hồn Khải là khải giáp đặc thù liên hệ trực tiếp với Thiên Ngưu Hồn và tư cách trấn thủ các huyệt của phòng tuyến Thiên Ngưu. Vương Lâm tiếp tục tiêu hóa cảm ngộ thu được từ lúc từng mặc Hồn Khải, còn trong hình ảnh cảm ứng ở một huyệt khác, bộ khải trên người một kẻ trấn thủ đã bị bàn tay đỏ thẫm đánh tan trước khi chủ nhân tử trận.","dacDiem":"Người mặc được Thiên Ngưu tán thành và có liên hệ với Thiên Ngưu thất huyệt.","congNang":["Liên hệ người mặc với Thiên Ngưu Hồn và tư cách trấn thủ một huyệt của phòng tuyến @c1785"],"nguon":["@c1785","@c1877","@c1880"],"tabs":{}},{"id":"ngoc-gian-truyen-lenh-cua-au-duong-chan","name":"Ngọc giản truyền lệnh của Âu Dương Chân","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Chưa rõ","soHuu":["Âu Dương Chân","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Ngọc giản do Âu Dương Chân giao cho Vương Lâm trong lúc truyền lệnh khẩn. Nó đủ để sử dụng Truyền Tống Trận ba lần và ghi vị trí cụ thể của trận tới Quy Nhất Tông.","detail":"Vật phẩm này xuất hiện khi Âu Dương Chân thay mặt truyền lệnh cho Vương Lâm. Ngọc giản có chức năng phục vụ di chuyển khẩn cấp tới Quy Nhất Tông trong kế hoạch chiến tranh của Thiên Ngưu Châu.","phanLoaiPhu":"ngọc giản truyền lệnh","congNang":["Sử dụng Truyền Tống Trận ba lần @c1786","Ghi vị trí cụ thể của Truyền Tống Trận tới Quy Nhất Tông @c1786"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Âu Dương Chân","tuChuong":"@c1786","denChuong":"@c1786","cachCoDuoc":"Tạo hoặc giữ trước khi truyền lệnh","trangThai":"đã giao"},{"ten":"Vương Lâm","tuChuong":"@c1786","denChuong":"","cachCoDuoc":"Được Âu Dương Chân giao để tới Quy Nhất Tông","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1786","loai":"đổi chủ","importance":"normal","giaiDoan":"Truyền lệnh tới Quy Nhất Tông","text":"Âu Dương Chân lấy ra ngọc giản và giao cho Vương Lâm để hắn dùng Truyền Tống Trận tới Quy Nhất Tông.","anchor":"Âu Dương Chân chụp vào hư không một cái, lập tức liền có một ngọc giản huyễn hóa ra"}]},"capNhatToi":"@c1786","nguon":["@c1786"]},{"id":"ngu-hanh-khai-kim-he","name":"Ngũ Hành Khải kim hệ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo Quy Nhất Tông","phamCap":"Chí bảo Quy Nhất Tông","soHuu":["Biên Vân"],"trangThai":"Biên Vân đang giữ","blurb":"Ngũ Hành Khải kim hệ là một phần kim hệ trong bộ Ngũ Hành Khải của Quy Nhất Tông. Tông chủban pháp bảo này cho Biên Vân sau khi phong ông làm trưởng lão kim hệ.","detail":"Ngũ Hành Khải kim hệ là bảo vật thuộc Quy Nhất Tông. Tông chủ trao nó cho Biên Vân vì công bảo vệ Thiên Ngưu huyệt đệ tứ, đồng thời phong ông làm trưởng lão kim hệ. Khi được ban, bảo vật hiện thành áo giáp vàng kim rồi hóa thành vô số sợi tơ chui vào thân thể Biên Vân.","phanLoaiPhu":"khải giáp kim hệ","hinhDang":"Áo giáp vàng kim hóa thành vô số sợi tơ nhập thể","nguonGoc":"Quy Nhất Tông","chuHienThoi":"Biên Vân","congNang":["Dạng khải giáp kim hệ hóa thành vô số sợi tơ nhập vào thân thể người được ban @c1787"],"chuSoHuu":[{"ten":"Biên Vân","tuChuong":"@c1787","denChuong":"","cachCoDuoc":"Được Tông chủ Quy Nhất Tông ban sau khi phong làm trưởng lão kim hệ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"đổi chủ","importance":"major","giaiDoan":"Ban cho Biên Vân","text":"Tông chủ Quy Nhất Tông ban Ngũ Hành Khải kim hệ cho Biên Vân sau khi phong ông làm trưởng lão kim hệ.","anchor":"tặng ngươi chí bảo của Quy Nhất Tông - Ngũ Hành Khải kim hệ","phamCap":"Chí bảo Quy Nhất Tông"}]},"boCha":"ngu-hanh-khai","dinhDanh":"bien-the","capNhatToi":"@c1787","nguon":["@c1787"],"dacDiem":"Hiện thành áo giáp vàng kim, có thể hóa thành vô số sợi tơ chui vào thân thể người mang."},{"id":"ngu-hanh-khai-thuy-he","name":"Ngũ Hành Khải thủy hệ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo Quy Nhất Tông","phamCap":"Chí bảo Quy Nhất Tông","soHuu":["Đường Giai"],"trangThai":"Đường Giai đang giữ","blurb":"Ngũ Hành Khải thủy hệ là một phần thủy hệ trong bộ Ngũ Hành Khải của Quy Nhất Tông. Tông chủ ban nó cho Đường Giai vì công bảo vệ Thiên Ngưu huyệt đệ lục.","detail":"Ngũ Hành Khải thủy hệ được Tông chủ Quy Nhất Tông ban cho Đường Giai (@c1787). Lam quang hóa thành biển nước bao phủ nàng rồi theo lỗ chân lông nhập vào thân thể, khiến nàng chấn động.","phanLoaiPhu":"khải giáp thủy hệ","hinhDang":"Lam quang hóa thành biển nước rồi nhập thể","nguonGoc":"Quy Nhất Tông","chuHienThoi":"Đường Giai","congNang":["Dạng khải giáp thủy hệ, lam quang hóa thành nước bao phủ và theo lỗ chân lông nhập vào thân thể người được ban @c1787"],"chuSoHuu":[{"ten":"Đường Giai","tuChuong":"@c1787","denChuong":"","cachCoDuoc":"Được Tông chủ Quy Nhất Tông ban vì công giữ đệ lục huyệt","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"đổi chủ","importance":"major","giaiDoan":"Ban cho Đường Giai","text":"Tông chủ Quy Nhất Tông ban Ngũ Hành Khải thủy hệ cho Đường Giai, để lam quang hóa nước nhập vào thân thể nàng.","anchor":"Ban cho ngươi chí bảo của Quy Nhất Tông, Ngũ Hành Khải thủy hệ","phamCap":"Chí bảo Quy Nhất Tông"}]},"boCha":"ngu-hanh-khai","dinhDanh":"bien-the","capNhatToi":"@c1787","nguon":["@c1787"],"dacDiem":"Một phần thủy hệ trong bộ Ngũ Hành Khải của Quy Nhất Tông; biểu hiện bằng lam quang hóa nước."},{"id":"do-linh-thu","name":"Đồ Linh Thứ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Tiên khí Quy Nhất Tông","phamCap":"Tiên khí","soHuu":["Vân Dật Phong"],"trangThai":"Vân Dật Phong đang giữ","blurb":"Đồ Linh Thứ là tiên khí của Quy Nhất Tông, được Tông chủ ban cho Vân Dật Phong. Vật có hình dạng nhỏ màu đen tựa chủy thủ hoặc trùy, mang chín gai sắc bén cùng khí tức khủng bố trong lần xuất hiện đầu tiên.","detail":"Đồ Linh Thứ vốn là tiên khí của Quy Nhất Tông, được Tông chủ trao cho Vân Dật Phong trong buổi ban thưởng cùng ngọc giản truyền thừa thần thông (@c1787). Vật này có dạng một thanh nhỏ màu đen với chín gai sắc bén, tỏa khí tức khiến người ta chú ý ngay từ lần đầu lộ diện.","phanLoaiPhu":"tiên khí công kích","hinhDang":"Chủy thủ hoặc trùy nhỏ màu đen có chín gai sắc bén","nguonGoc":"Quy Nhất Tông","chuHienThoi":"Vân Dật Phong","dacDiem":"Hình dạng nhỏ màu đen tựa chủy thủ hoặc trùy, mang chín gai sắc bén và khí tức khủng bố trong lần xuất hiện đầu tiên.","chuSoHuu":[{"ten":"Vân Dật Phong","tuChuong":"@c1787","denChuong":"","cachCoDuoc":"Được Tông chủ Quy Nhất Tông ban sau công giữ huyệt","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"đổi chủ","importance":"major","giaiDoan":"Ban cho Vân Dật Phong","text":"Tông chủ Quy Nhất Tông ban tiên khí Đồ Linh Thứ cho Vân Dật Phong cùng truyền thừa thần thông.","anchor":"ban cho ngươi tiên khí Đồ Linh Thứ của bổn tông","phamCap":"Tiên khí"}]},"dinhDanh":"goc","capNhatToi":"@c1787","nguon":["@c1787"]},{"id":"ngoc-gian-truyen-thua-quy-nhat-tong","name":"Ngọc giản truyền thừa Quy Nhất Tông","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vân Dật Phong"],"trangThai":"Vân Dật Phong đang giữ","blurb":"Ngọc giản đi kèm phần thưởng truyền thừa của Quy Nhất Tông cho Vân Dật Phong. Nó được đưa ra từ đại điện cùng Đồ Linh Thứ.","detail":"Khi Tông chủ Quy Nhất Tông ban thưởng cho Vân Dật Phong, hai cầu vồng từ đại điện bay ra, trong đó một người cầm ngọc giản, người còn lại cầm Đồ Linh Thứ. Ngọc giản này gắn với một trong bốn loại thần thông truyền thừa của Quy Nhất Tông.","phanLoaiPhu":"ngọc giản truyền thừa","nguonGoc":"Quy Nhất Tông","chuHienThoi":"Vân Dật Phong","congNang":["Chứa hoặc đại diện cho truyền thừa thần thông Quy Nhất Tông được ban cho Vân Dật Phong @c1787"],"chuSoHuu":[{"ten":"Vân Dật Phong","tuChuong":"@c1787","denChuong":"","cachCoDuoc":"Được đưa ra từ đại điện trong phần thưởng của Tông chủ Quy Nhất Tông","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"xuất hiện","importance":"normal","giaiDoan":"Trao truyền thừa","text":"Ngọc giản truyền thừa được mang ra từ đại điện cùng Đồ Linh Thứ để trao cho Vân Dật Phong.","anchor":"Một người trong đó cầm ngọc giản, người còn lại cầm một thanh có chủy thủ màu đen","phamCap":"Không rõ"}]},"dinhDanh":"goc","capNhatToi":"@c1787","nguon":["@c1787"]},{"id":"ngu-hanh-khai-hoa-he","name":"Ngũ Hành Khải hỏa hệ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo Quy Nhất Tông","phamCap":"Chí bảo Quy Nhất Tông","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Ngũ Hành Khải hỏa hệ là một phần hỏa hệ trong bộ Ngũ Hành Khải của Quy Nhất Tông. Tông chủ ban nó cho Vương Lâm vì công giữ Thiên Ngưu huyệt đệ tam, nhưng đây là phần thưởng duy nhất của hắn.","detail":"Ngũ Hành Khải hỏa hệ được Tông chủ Quy Nhất Tông ban cho Vương Lâm. Từ trong đại điện, biển lửa hóa thành khôi giáp bốc cháy lao về phía hắn, song việc hắn chỉ nhận một phần thưởng tạo ra sự bất công rõ rệt so với ba người còn lại.","phanLoaiPhu":"khải giáp hỏa hệ","hinhDang":"Biển lửa hóa thành khôi giáp bốc cháy","nguonGoc":"Quy Nhất Tông","chuHienThoi":"Vương Lâm","congNang":["Dạng khải giáp hỏa hệ được ngưng từ biển lửa trong đại điện @c1787"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1787","denChuong":"","cachCoDuoc":"Được Tông chủ Quy Nhất Tông ban vì công giữ Thiên Ngưu huyệt đệ tam","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"đổi chủ","importance":"major","giaiDoan":"Ban cho Vương Lâm","text":"Tông chủ Quy Nhất Tông ban Ngũ Hành Khải hỏa hệ cho Vương Lâm, nhưng chỉ cho hắn một phần thưởng duy nhất.","anchor":"ta ban cho ngươi Ngũ Hành Khải hỏa hệ","phamCap":"Chí bảo Quy Nhất Tông"}]},"boCha":"ngu-hanh-khai","dinhDanh":"bien-the","capNhatToi":"@c1787","nguon":["@c1787"]},{"id":"thien-nguu-chau-hat","name":"Thiên Ngưu Châu","cn":"","aliases":[],"category":"than-khi","categoryLabel":"Chí bảo tông môn","phamCap":"chí bảo","soHuu":["Đại Hồn Môn","Quy Nhất Tông"],"trangThai":"tồn tại","blurb":"Thiên Ngưu Châu là chí bảo chỉ có bảy hạt, do Đại Hồn Môn và Quy Nhất Tông phát hiện khi mở Thiên Ngưu thất huyệt. Quy Nhất Tông giữ ba hạt, Đại Hồn Môn giữ bốn hạt, và một viên từng bị đưa vào trọng thưởng truy sát Vương Lâm.","detail":"Thiên Ngưu Châu được Đại Hồn Môn và Quy Nhất Tông phát hiện khi mở Thiên Ngưu thất huyệt, toàn bộ chỉ có bảy hạt, trong đó Quy Nhất Tông giữ ba hạt và Đại Hồn Môn giữ bốn hạt @c1788. Châu này có thể dùng để tạo pháp bảo và biến đổi thời gian tu luyện, nhưng công dụng quan trọng nhất là duy trì Thiên Ngưu Hồn, giúp người mặc Hồn Khải vẫn sử dụng được Hồn Khải khi rời xa Thiên Ngưu Châu. Một viên trong số đó từng được đưa vào trọng thưởng truy sát Vương Lâm @c1788.","phanLoaiPhu":"hạt châu chí bảo","nguonGoc":"Được Đại Hồn Môn và Quy Nhất Tông phát hiện khi mở Thiên Ngưu thất huyệt","congNang":["Có thể tạo pháp bảo @c1788","Có thể biến đổi thời gian tu luyện @c1788","Duy trì Thiên Ngưu Hồn để người mặc Hồn Khải vẫn sử dụng được Hồn Khải khi rời xa Thiên Ngưu Châu @c1788"],"chuSoHuu":[{"ten":"Quy Nhất Tông","tuChuong":"@c1788","denChuong":"","cachCoDuoc":"Giữ ba trong bảy hạt được phát hiện ở Thiên Ngưu thất huyệt","trangThai":"đang giữ"},{"ten":"Đại Hồn Môn","tuChuong":"@c1788","denChuong":"","cachCoDuoc":"Giữ bốn trong bảy hạt được phát hiện ở Thiên Ngưu thất huyệt","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1788","loai":"xuất hiện","importance":"major","giaiDoan":"Chí bảo treo thưởng","text":"Thiên Ngưu Châu được hé lộ là chí bảo chỉ có bảy hạt, có thể duy trì Thiên Ngưu Hồn cho Hồn Khải và bị đưa vào trọng thưởng truy sát Vương Lâm.","anchor":"Điều quan trọng nhất là nhờ có hạt châu này, có thể giữ được Thiên Ngưu Hồn"}]},"capNhatToi":"@c1788","nguon":["@c1788"],"dacDiem":"Chí bảo chỉ có bảy hạt, do Đại Hồn Môn và Quy Nhất Tông phân giữ (bốn và ba hạt) @c1788"},{"id":"quy-pham-pho-ky-cua-dai-hon-mon","name":"Quỷ Phàm phó kỳ của Đại Hồn Môn","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Phó kỳ đại trận hộ sơn","phamCap":"không rõ","soHuu":["Đại Hồn Môn"],"trangThai":"bị nêu làm treo thưởng","blurb":"Quỷ Phàm phó kỳ của Đại Hồn Môn là phần thưởng được nêu cho người giết Vương Lâm trong Hồn Lệnh.","detail":"Nếu có phó kỳ này trong tay, dù ở khoảng cách rất xa vẫn có thể thi triển uy lực lớn của Quỷ Phàm đại trận hộ sơn Đại Hồn Môn. Nó được đưa vào cùng Ngũ Hành Khải hỏa hệ và một viên Thiên Ngưu Châu làm trọng thưởng truy sát Vương Lâm.","phanLoaiPhu":"phó kỳ trận pháp","congNang":["Cho phép thi triển uy lực lớn của Quỷ Phàm đại trận hộ sơn Đại Hồn Môn từ khoảng cách rất xa @c1788"],"chuSoHuu":[{"ten":"Đại Hồn Môn","tuChuong":"@c1788","denChuong":"","cachCoDuoc":"Phó kỳ thuộc đại trận hộ sơn của Đại Hồn Môn","trangThai":"đang bị nêu làm treo thưởng"}],"tabs":{"tienTrinh":[{"chuong":"@c1788","loai":"xuất hiện","importance":"normal","giaiDoan":"Trọng thưởng truy sát","text":"Quỷ Phàm phó kỳ của Đại Hồn Môn được đưa vào phần thưởng truy sát Vương Lâm và lộ công năng thi triển uy lực Quỷ Phàm đại trận từ xa.","anchor":"nếu có cây Quỷ Phàm phó kỳ này trong tay thì dù ở khoảng cách rất xa vẫn có thể thi triển"}]},"capNhatToi":"@c1788","nguon":["@c1788"]},{"id":"hon-lenh","name":"Hồn Lệnh","cn":"","category":"khac","categoryLabel":"Lệnh truy sát","phamCap":"Không rõ","soHuu":["Tông chủ Quy Nhất Tông","Biên Vân"],"trangThai":"đang được dùng làm căn cứ truy sát","blurb":"Lệnh truy sát do Tông chủ Quy Nhất Tông tự mình phát ra nhằm truy sát Vương Lâm phản bội.","detail":"Biên Vân xem Hồn Lệnh là căn cứ để truy sát Vương Lâm và đổi tặng phẩm. Hắn cũng dùng việc chấp hành Hồn Lệnh để tự cho rằng Đại Hồn Môn không thể trách cứ mình.","congNang":["Làm căn cứ truy sát Vương Lâm phản bội Quy Nhất Tông @c1789"],"chuSoHuu":[{"ten":"Tông chủ Quy Nhất Tông","tuChuong":"@c1789","denChuong":"","cachCoDuoc":"tự mình phát ra","trangThai":"người phát lệnh"},{"ten":"Biên Vân","tuChuong":"@c1789","denChuong":"","cachCoDuoc":"dùng làm căn cứ truy sát","trangThai":"đang lợi dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"xuất hiện","importance":"normal","giaiDoan":"Căn cứ truy sát","text":"Biên Vân dùng Hồn Lệnh do Tông chủ Quy Nhất Tông phát ra làm lý do truy sát Vương Lâm.","anchor":"Hồn Lệnh do Tông chủ Quy Nhất Tông tự mình phát ra truy sát Vương Lâm phản bội"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"hon-khai-cua-duong-giai","name":"Hồn Khải của Đường Giai","cn":"","category":"phap-bao","categoryLabel":"Hồn khải","phamCap":"Không rõ","soHuu":["Đường Giai"],"trangThai":"đang sử dụng","blurb":"Hồn Khải giúp Đường Giai tăng tu vi lên Không Kiếp trung kỳ và gia tăng uy lực phong ấn.","detail":"Sau khi Đường Giai mặc Hồn Khải, tu vi của nàng đạt tới Không Kiếp trung kỳ. Nhờ đó, uy lực Bát môn phong được tăng lên nhiều lần khi nàng dùng để phong khóa Biên Vân.","congNang":["Tăng tu vi của Đường Giai lên Không Kiếp trung kỳ và tăng uy lực Bát môn phong @c1789"],"chuSoHuu":[{"ten":"Đường Giai","tuChuong":"@c1789","denChuong":"","cachCoDuoc":"đang sở hữu và mặc khi giao chiến","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"dùng","importance":"normal","giaiDoan":"Tăng uy lực phong ấn","text":"Đường Giai mặc Hồn Khải, đạt tu vi Không Kiếp trung kỳ và khiến Bát môn phong mạnh hơn nhiều lần.","anchor":"sau khi nàng mặc Hồn Khải vào, tu vi đạt tới Không Kiếp trung kỳ thì uy lực của nó lại được gấp lên rất nhiều lần"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"tieu-thuan-mau-trang","name":"Tiểu thuẫn màu trắng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"Không rõ","soHuu":["Biên Vân"],"trangThai":"nứt vỡ, mất sức chống cự","blurb":"Pháp bảo phòng ngự Biên Vân gọi ra để đỡ Thất Thải Thương của Vương Lâm.","detail":"Biên Vân gọi tiểu thuẫn màu trắng ra trước người để ngăn Thất Thải Thương. Sau va chạm, tiểu thuẫn xuất hiện vết nứt và bị lục chỉ ma ấn đánh tiếp tới mức không còn sức chống cự.","congNang":["Phòng ngự trực diện trước thần thông công kích @c1789"],"chuSoHuu":[{"ten":"Biên Vân","tuChuong":"@c1789","denChuong":"","cachCoDuoc":"gọi ra khi giao chiến","trangThai":"hư tổn"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Đỡ Thất Thải Thương","text":"Biên Vân gọi tiểu thuẫn màu trắng ra phòng ngự, nhưng nó nứt vỡ sau khi chịu Thất Thải Thương và lục chỉ ma ấn.","anchor":"lập tức trước người xuất hiện một tiểu thuẫn màu trắng nhỏ"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"hon-khai-cua-bien-van","name":"Hồn Khải của Biên Vân","cn":"","category":"phap-bao","categoryLabel":"Khải giáp hồn bảo","phamCap":"không rõ","soHuu":["Biên Vân"],"trangThai":"đang thuộc Biên Vân","blurb":"Hồn Khải Biên Vân mặc trong trận chiến với Vương Lâm, có thể tăng mạnh tu vi và hóa thành Thiên Ngưu Hồn.","detail":"Khi Biên Vân thi triển thần thông, Hồn Khải khiến hắn tạm thời không thể mặc giáp, chuyển thành Thiên Ngưu Hồn để đánh tan Tàn Dạ. Sau khi rời giáp, mức tăng cường của Biên Vân biến mất, khí tức rơi từ Không Kiếp hậu kỳ về Không Kiếp trung kỳ.","congNang":["Tăng cường tu vi khi mặc trên người @c1790","Tạm hóa thành Thiên Ngưu Hồn để công phá Tàn Dạ @c1790"],"chuSoHuu":[{"ten":"Biên Vân","tuChuong":"@c1790","denChuong":"","cachCoDuoc":"đang sở hữu khi giao chiến","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1790","loai":"dùng","importance":"normal","giaiDoan":"Phá Tàn Dạ","text":"Biên Vân dùng Hồn Khải hóa thành Thiên Ngưu Hồn để đánh tan Tàn Dạ, nhưng bản thân mất trạng thái tăng cường sau đó.","anchor":"Thần thông này bất ngờ lại khiến hắn phải tạm thời không thể mặc Hồn Khải"}]},"nguon":["@c1790"]},{"id":"vien-da-mau-den-thanh-nguu-giao","name":"Viên đá màu đen Thanh Ngưu giao","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm","Đỗ Thanh"],"trangThai":"đã giao cho Vương Lâm","blurb":"Viên đá màu đen Thanh Ngưu giao là vật do Thanh Ngưu lão tổ sai Đỗ Thanh mang tới Thất Đạo Tông giao cho Vương Lâm. Bề ngoài tầm thường nhưng bên trong ẩn chứa khí tức Hồn Diễn Đạo.","detail":"Viên đá do Thanh Ngưu lão tổ ủy thác, được Đỗ Thanh mang tới Thất Đạo Tông giao cho Vương Lâm. Bề ngoài viên đá tầm thường, Đỗ Thanh từng dùng mọi cách dọc đường vẫn không tìm ra manh mối. Khi Vương Lâm nhận lấy, hắn cảm nhận được khí tức Hồn Diễn Đạo ẩn chứa trong đó @c1790.","dacDiem":"Bề ngoài tầm thường nhưng ẩn chứa khí tức Hồn Diễn Đạo.","congNang":["Chứa khí tức Hồn Diễn Đạo mà Vương Lâm có thể cảm nhận @c1790"],"chuSoHuu":[{"ten":"Đỗ Thanh","tuChuong":"@c1790","denChuong":"@c1790","cachCoDuoc":"nhận theo lệnh Thanh Ngưu lão tổ để mang tới Thất Đạo Tông","trangThai":"đã giao"},{"ten":"Vương Lâm","tuChuong":"@c1790","denChuong":"","cachCoDuoc":"Đỗ Thanh giao tại Thất Đạo Tông","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1790","loai":"đổi chủ","importance":"major","giaiDoan":"Giao vật tại Thất Đạo Tông","text":"Đỗ Thanh giao viên đá màu đen cho Vương Lâm theo lệnh Thanh Ngưu lão tổ, và Vương Lâm cảm nhận được khí tức Hồn Diễn Đạo bên trong.","anchor":"Đỗ Thanh cầm trong tay dọc theo đường đi đã dùng hết mọi biện pháp muốn tìm ra manh mối"}]},"nguon":["@c1790"]},{"id":"ao-giap-hinh-nguoi-quy-nhat-tong","name":"Áo giáp hình người Quy Nhất Tông","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Áo giáp / Hồn Khải","phamCap":"Cấp cao trong hệ áo giáp Quy Nhất Tông","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm thu nhận","blurb":"Áo giáp hình người Quy Nhất Tông là một pháp bảo mang khí tức thổ hệ, xuất hiện từ quầng sáng thứ nhất sau khi hòn đá màu đen được mở ra. Cấp bậc của nó vượt xa những áo giáp Quy Nhất Tông thông thường mà Vương Lâm từng thấy, được Vương Lâm thu nhận về (@c1791).","detail":"Bộ áo giáp là một trong bốn món bồi thường mà Thanh Ngưu lão tổ chuẩn bị cho Vương Lâm. Nó hiện ra trong quầng sáng thứ nhất sau khi hòn đá màu đen được mở, mang khí tức thổ hệ và có cấp bậc vượt xa những áo giáp Quy Nhất Tông thông thường. Vương Lâm nhận định loại áo giáp này ngay trong Quy Nhất Tông cũng không có nhiều, cho thấy giá trị rất cao. Tính tới mốc mới nhất, pháp bảo đã được Vương Lâm thu nhận (@c1791).","phanLoaiPhu":"Hồn Khải thổ hệ","dacDiem":"Mang khí tức thổ hệ, cấp bậc vượt xa áo giáp Quy Nhất Tông thông thường.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1791","denChuong":"","cachCoDuoc":"Nhận từ hòn đá màu đen do Thanh Ngưu lão tổ chuẩn bị.","trangThai":"đang giữ"}],"congNang":["Có thể làm Hồn Khải đồng hành cùng Vương Lâm sau khi Thiên Ngưu Hồn dung nhập vào Thiên Ngưu Châu."],"tabs":{"tienTrinh":[{"chuong":"@c1791","loai":"đổi chủ","importance":"major","giaiDoan":"Từ hòn đá màu đen chuyển sang Vương Lâm","text":"Áo giáp hình người Quy Nhất Tông hiện ra trong quầng sáng thứ nhất và được Vương Lâm thu nhận.","anchor":"Bộ áo giáp hình người nhất định ngay trong Quy Nhất Tông cũng không có nhiều","phamCap":"Cấp cao trong hệ áo giáp Quy Nhất Tông"}]},"capNhatToi":"@c1791","nguon":["@c1791"]},{"id":"mai-rua-ban-do-dong-chau","name":"Mai rùa bản đồ Đông Châu","cn":"","aliases":[],"category":"khac","categoryLabel":"Bản đồ / vật ghi lời nhắn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm thu nhận","blurb":"Mai rùa bản đồ Đông Châu là tấm mai rùa tàn phá lộ ra từ quầng sáng thứ tư trong hòn đá màu đen. Bên trong chứa bản đồ toàn bộ Đông Châu cùng lời nhắn của Thanh Ngưu lão tổ dành cho Vương Lâm.","detail":"Vật này xuất hiện cùng lời hẹn ba trăm năm của Thanh Ngưu lão tổ dành cho Vương Lâm (@c1791). Nó giúp Vương Lâm xác định vị trí Đông Lâm Tông tại Đại Thánh Châu và định hướng rời Thiên Ngưu Châu. Lời nhắn ngắn gọn hẹn hắn ba trăm năm sau quay về Đại Hồn Môn.","hinhDang":"Mai rùa tàn phá có đồ án khắc bên trên.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1791","denChuong":"","cachCoDuoc":"Nhận từ hòn đá màu đen do Thanh Ngưu lão tổ chuẩn bị.","trangThai":"đang giữ"}],"congNang":["Chứa bản đồ toàn bộ Đông Châu.","Lưu lời nhắn của Thanh Ngưu lão tổ, hẹn Vương Lâm ba trăm năm sau quay về Đại Hồn Môn. @c1791"],"tabs":{"tienTrinh":[{"chuong":"@c1791","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện ra trong quầng sáng thứ tư","text":"Mai rùa bản đồ Đông Châu lộ ra cùng lời hẹn ba trăm năm của Thanh Ngưu lão tổ dành cho Vương Lâm.","anchor":"Bên trong mai rùa kia là bản đồ của toàn bộ Đông Châu","phamCap":"Không rõ"}]},"capNhatToi":"@c1791","nguon":["@c1791"],"dacDiem":"Là mai rùa tàn phá, lộ ra từ quầng sáng thứ tư trong hòn đá màu đen."},{"id":"thien-nghich","name":"Thiên Nghịch","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Hạt châu / trọng bảo","phamCap":"Rất cao","soHuu":["Vương Lâm"],"trangThai":"Đã dung nhập hồn phách Vương Lâm","blurb":"Thiên Nghịch được nhắc khi Vương Lâm so sánh hạt châu màu nâu trong quầng sáng thứ ba với trọng bảo đã dung nhập vào hồn phách mình.","detail":"Trong chương này Thiên Nghịch không xuất hiện như vật ngoài thân, chỉ được dùng làm đối chiếu để Vương Lâm nhận ra Thiên Ngưu Châu kém xa Thiên Nghịch về cấp bậc.","dacDiem":"Đã dung nhập vào hồn phách Vương Lâm.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1791","denChuong":"","cachCoDuoc":"Đã dung nhập vào hồn phách từ trước chương này.","trangThai":"đã dung nhập"}],"tabs":{"tienTrinh":[{"chuong":"@c1791","loai":"nhắc tới","importance":"bridge","giaiDoan":"Được dùng làm đối chiếu","text":"Thiên Nghịch được nhắc khi Vương Lâm so sánh hạt châu màu nâu với trọng bảo đã dung nhập vào hồn phách mình.","anchor":"Thiên Nghịch đã dung nhập vào trong hồn phách của mình","phamCap":"Rất cao"}]},"capNhatToi":"@c1791","nguon":["@c1791"]},{"id":"thanh-kiem-co-kinh-mau-vang-kim-cua-van-khong","name":"Thanh kiếm cổ kính màu vàng kim của Vân Không","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo do Đại Thiên Tôn ngưng tụ","phamCap":"Dấu vết thần thông Đại Thiên Tôn","soHuu":["Vân Không"],"trangThai":"bị phá hủy","blurb":"Thanh kiếm cổ kính màu vàng kim là pháp bảo mà Vân Không lấy ra dùng trong nhát đánh cuối khi đối đầu Vương Lâm. Kiếm mang khí tức hoàng tộc và dấu vết thần thông của Đại Thiên Tôn, song khi chạm phải kim ấn của Vương Lâm thì bị cuốn đi và vỡ thành vô số mảnh nhỏ.","detail":"Thanh kiếm cổ kính màu vàng kim do Đại Thiên Tôn dùng thần thông từ hư vô sinh ra, vì thế mang khí tức hoàng tộc cùng dấu vết thần thông của Đại Thiên Tôn. Vân Không lấy nó ra làm nhát công kích cuối nhằm tiếp tục trì hoãn Vương Lâm. Khi đối đầu với kim ấn do Vương Lâm gọi ra, thanh kiếm bị cuốn đi và vỡ thành vô số mảnh nhỏ @c1793.","phanLoaiPhu":"Kiếm","hinhDang":"Thanh kiếm cổ kính màu vàng kim","nguonGoc":"Do Đại Thiên Tôn dùng thần thông từ hư vô sinh ra","uyLuc":"Có thể trở thành nhát công kích cuối của Vân Không khi đối đầu Vương Lâm.","dacDiem":"Mang khí tức hoàng tộc và dấu vết thần thông Đại Thiên Tôn.","chuHienThoi":"Vân Không","congNang":["Dùng làm pháp bảo công kích trực diện trong nhát kiếm cuối của Vân Không @c1793"],"chuSoHuu":[{"ten":"Vân Không","tuChuong":"@c1793","denChuong":"@c1793","cachCoDuoc":"Mang ra trong giao chiến với Vương Lâm","trangThai":"mất do bị phá hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c1793","loai":"dùng","importance":"major","giaiDoan":"Đối kháng kim ấn","text":"Vân Không dùng thanh kiếm cổ kính màu vàng kim mang khí tức hoàng tộc đánh Vương Lâm, nhưng thanh kiếm bị kim ấn đánh vỡ thành vô số mảnh.","anchor":"Bất ngờ một thanh kiếm cổ kính, lộ ra khí tức của hoàng tộc xuất hiện trên tay hắn","phamCap":"Dấu vết thần thông Đại Thiên Tôn"}]},"capNhatToi":"@c1793","nguon":["@c1793"]},{"id":"kim-an-cua-vuong-lam","name":"Kim ấn của Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo do Đại Thiên Tôn ngưng tụ","phamCap":"Dấu vết thần thông Đại Thiên Tôn","soHuu":["Vương Lâm"],"trangThai":"nứt sâu nhưng còn giữ","blurb":"Kim ấn được Vương Lâm gọi ra để đối kháng thanh kiếm cổ kính màu vàng kim của Vân Không. Nó đánh nát kiếm đối phương nhưng bản thân cũng xuất hiện vết nứt sâu.","detail":"Trong lúc Vân Không dùng pháp bảo có dấu vết Đại Thiên Tôn, Vương Lâm cũng gọi kim ấn ra đối kháng. Kim ấn cuốn nát thanh kiếm cổ kính của Vân Không, ánh sáng sau đó ảm đạm và được Vương Lâm thu lại.","phanLoaiPhu":"Ấn","hinhDang":"Kim ấn","uyLuc":"Đánh nát thanh kiếm cổ kính màu vàng kim của Vân Không.","dacDiem":"Chứa tín niệm lực nhiều hơn kiếm của Vân Không nhưng bị nứt sâu sau va chạm.","chuHienThoi":"Vương Lâm","congNang":["Đối kháng và phá hủy pháp bảo mang dấu vết Đại Thiên Tôn của Vân Không @c1793"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1793","denChuong":"","cachCoDuoc":"Đã có trong tay và gọi ra khi giao chiến","trangThai":"đang giữ, có vết nứt sâu"}],"tabs":{"tienTrinh":[{"chuong":"@c1793","loai":"dùng","importance":"normal","giaiDoan":"Phá kiếm Vân Không","text":"Vương Lâm gọi kim ấn ra để đối kháng thanh kiếm cổ kính của Vân Không, đánh nát kiếm nhưng kim ấn xuất hiện vết nứt sâu.","anchor":"Kim ấn của Vương Lâm xuất hiện một vết nứt rất sâu nhưng không bị tan vỡ","phamCap":"Dấu vết thần thông Đại Thiên Tôn"}]},"capNhatToi":"@c1793","nguon":["@c1793"]},{"id":"dau-lau-tu-si-cuc-thien-thao-nguyen","name":"Đầu lâu tu sĩ Cực Thiên thảo nguyên","cn":"","category":"khac","categoryLabel":"Vật phẩm khủng bố tinh thần","phamCap":"Không rõ","soHuu":["Đạo Ma Tông"],"trangThai":"bị ném ra trước Vương Lâm","blurb":"Hàng trăm đầu lâu của các tu sĩ Cực Thiên thảo nguyên từng cùng Vương Lâm chiến đấu. Đạo Ma Tông dùng chúng làm đại lễ để kích nộ Vương Lâm, khiến hắn lập lời thề diệt sạch toàn tông.","detail":"Các tu sĩ Đạo Ma Tông ném ra hàng trăm đầu lâu thuộc những người từng sống sót ở Cực Thiên thảo nguyên và quen mặt với Vương Lâm từ Thiên Ngưu đệ tam huyệt. Hành động này nhằm kích nộ Vương Lâm, dẫn tới việc hắn lập lời thề giết sạch toàn tông Đạo Ma Tông.","phanLoaiPhu":"Đầu lâu chiến lợi phẩm","congNang":["Kích nộ Vương Lâm và ép xung đột với Đạo Ma Tông thành lời thề diệt tông @c1793"],"chuSoHuu":[{"ten":"Đạo Ma Tông","tuChuong":"@c1793","denChuong":"@c1793","cachCoDuoc":"Sát hại nhiều tu sĩ Cực Thiên thảo nguyên","trangThai":"đã ném ra"}],"tabs":{"tienTrinh":[{"chuong":"@c1793","loai":"dùng","importance":"major","giaiDoan":"Đại lễ thứ nhất","text":"Đạo Ma Tông ném ra hàng trăm đầu lâu tu sĩ Cực Thiên thảo nguyên để kích nộ Vương Lâm.","anchor":"Mấy trăm đầu người chiếm gần một nửa số người còn sống tại Cực Thiên thảo nguyên","phamCap":"Không rõ"}]},"capNhatToi":"@c1793","nguon":["@c1793"]}]};
